SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A proton (mass 1.67 × 10⁻²⁷ kg) moves with a speed of 5 × 10⁶ m/s perpendicular to a magnetic field of 0.5 T. The radius of the circular path described by the proton is (charge of proton = 1.6 × 10⁻¹⁹ C):", "explanation": "When a charged particle moves perpendicular to a magnetic field, it follows a circular path. The radius is given by r = mv/(qB). Substituting: r = (1.67 × 10⁻²⁷ × 5 × 10⁶) / (1.6 × 10⁻¹⁹ × 0.5) = (8.35 × 10⁻²¹) / (8.0 × 10⁻²⁰) = 0.104 m ≈ 0.1 m.", "correct_answer": "B", "concept_tags": ["circular-motion", "radius-of-path", "proton", "magnetic-field"], "payload": {"question_id": "cuet-phy-magmov-force-05", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 m", "is_correct": false}, {"key": "B", "text": "0.1 m", "is_correct": true}, {"key": "C", "text": "1.0 m", "is_correct": false}, {"key": "D", "text": "0.05 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Re-check the calculation: r = mv/(qB) = (1.67 × 10⁻²⁷ × 5 × 10⁶)/(1.6 × 10⁻¹⁹ × 0.5) ≈ 0.1 m.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "C", "hint": "1.0 m is ten times the correct answer. Ensure proper handling of exponents in the numerator and denominator.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "D", "hint": "0.05 m results from an incorrect factor of 2. The formula r = mv/(qB) does not include any additional numerical factor.", "misconception": "Introducing an extraneous factor in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron (charge e, mass m) and a proton (charge e, mass M) enter a uniform magnetic field perpendicularly with the same kinetic energy. The ratio of radii of their circular paths (rₑ/rₚ) is:", "explanation": "The radius of circular motion in a magnetic field is r = mv/(eB). Since kinetic energy K = ½mv², we get v = √(2K/m), so r = m√(2K/m)/(eB) = √(2mK)/(eB). Therefore rₑ/rₚ = √(m/M). Since the electron mass m is much smaller than proton mass M, the electron follows a much smaller circle.", "correct_answer": "C", "concept_tags": ["radius-ratio", "kinetic-energy", "electron", "proton", "circular-motion"], "payload": {"question_id": "cuet-phy-magmov-force-06", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "m/M", "is_correct": false}, {"key": "B", "text": "M/m", "is_correct": false}, {"key": "C", "text": "√(m/M)", "is_correct": true}, {"key": "D", "text": "√(M/m)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the ratio if r were directly proportional to mass (at same velocity). But at same kinetic energy, r = √(2mK)/(eB), giving a square-root dependence.", "misconception": "Using r = mv/(qB) without converting velocity in terms of kinetic energy"}, {"option_key": "B", "hint": "M/m > 1 would mean the electron has a larger radius than the proton, which contradicts the fact that the lighter particle has a smaller radius at equal KE.", "misconception": "Inverting the mass ratio"}, {"option_key": "D", "hint": "√(M/m) > 1 would imply rₑ > rₚ. Since the electron is lighter, it has less momentum at the same KE and hence a smaller radius.", "misconception": "Confusing which particle has the larger radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A straight conductor of length 0.5 m carrying a current of 2 A is placed in a uniform magnetic field of 0.4 T at an angle of 30° to the field. The force on the conductor is:", "explanation": "The force on a current-carrying conductor in a magnetic field is F = BIL sinθ. Substituting the given values: F = 0.4 × 2 × 0.5 × sin 30° = 0.4 × 2 × 0.5 × 0.5 = 0.2 N.", "correct_answer": "D", "concept_tags": ["force-on-conductor", "current-carrying-conductor", "magnetic-field", "numerical"], "payload": {"question_id": "cuet-phy-magmov-force-07", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "apply", "options": [{"key": "A", "text": "0.4 N", "is_correct": false}, {"key": "B", "text": "0.1 N", "is_correct": false}, {"key": "C", "text": "0.8 N", "is_correct": false}, {"key": "D", "text": "0.2 N", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.4 N would be the answer if sinθ = 1 (θ = 90°). Here θ = 30°, so sin 30° = 0.5 must be included.", "misconception": "Forgetting the sinθ factor when the conductor is not perpendicular to B"}, {"option_key": "B", "hint": "0.1 N would result from using sin 30° twice or an arithmetic error. Check: F = 0.4 × 2 × 0.5 × 0.5 = 0.2 N.", "misconception": "Arithmetic error in multiplication"}, {"option_key": "C", "hint": "0.8 N would result from ignoring sin 30° and also doubling the result. F = BIL sinθ, not 2BIL.", "misconception": "Using an incorrect formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a velocity selector, a charged particle passes undeflected when:", "explanation": "In a velocity selector, crossed electric (E) and magnetic (B) fields are applied. The electric force qE and the magnetic force qvB act in opposite directions. The particle passes undeflected when these forces balance: qE = qvB, giving v = E/B. This condition is independent of the charge and mass of the particle.", "correct_answer": "C", "concept_tags": ["velocity-selector", "electric-field", "magnetic-field", "undeflected"], "payload": {"question_id": "cuet-phy-magmov-force-08", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "v = B/E", "is_correct": false}, {"key": "B", "text": "v = EB", "is_correct": false}, {"key": "C", "text": "v = E/B", "is_correct": true}, {"key": "D", "text": "v = E²/B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "B/E is the inverse of the correct answer. From qE = qvB, solving for v gives v = E/B, not B/E.", "misconception": "Inverting the ratio while solving qE = qvB"}, {"option_key": "B", "hint": "EB is dimensionally incorrect for velocity. E has units V/m and B has units T, so EB would have units V·T/m, not m/s.", "misconception": "Incorrectly combining E and B"}, {"option_key": "D", "hint": "E²/B does not follow from balancing electric and magnetic forces. The correct derivation gives v = E/B.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charged particle moves in a helical path in a uniform magnetic field. This happens when the velocity of the particle:", "explanation": "When a charged particle enters a magnetic field with its velocity at an angle to the field (neither parallel nor perpendicular), the velocity component perpendicular to B causes circular motion while the component parallel to B remains unaffected. The combination of circular motion and uniform linear motion along B produces a helical (spiral) path.", "correct_answer": "D", "concept_tags": ["helical-motion", "velocity-components", "magnetic-field"], "payload": {"question_id": "cuet-phy-magmov-force-09", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "Is perpendicular to B", "is_correct": false}, {"key": "B", "text": "Is parallel to B", "is_correct": false}, {"key": "C", "text": "Is zero", "is_correct": false}, {"key": "D", "text": "Has components both parallel and perpendicular to B", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "When velocity is purely perpendicular to B, the particle follows a circular path, not a helical one.", "misconception": "Confusing circular and helical paths"}, {"option_key": "B", "hint": "When velocity is parallel to B, there is no magnetic force and the particle moves in a straight line.", "misconception": "Not recognizing that parallel motion produces zero force"}, {"option_key": "C", "hint": "If velocity is zero, there is no motion at all and hence no path of any kind.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force per unit length between two long parallel conductors carrying currents I₁ and I₂ separated by a distance d is given by:", "explanation": "The magnetic field produced by conductor 1 at the location of conductor 2 is B₁ = μ₀I₁/(2πd). The force per unit length on conductor 2 is F/L = B₁I₂ = μ₀I₁I₂/(2πd). This expression is fundamental and is used to define the SI unit of current (ampere).", "correct_answer": "B", "concept_tags": ["force-per-unit-length", "parallel-conductors", "ampere-definition"], "payload": {"question_id": "cuet-phy-magmov-force-10", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I₁I₂/(4πd)", "is_correct": false}, {"key": "B", "text": "μ₀I₁I₂/(2πd)", "is_correct": true}, {"key": "C", "text": "μ₀I₁I₂/(2πd²)", "is_correct": false}, {"key": "D", "text": "μ₀I₁I₂d/(2π)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The factor is 2π in the denominator, not 4π. The field of a long wire is B = μ₀I/(2πd), and force/length = BI₂ = μ₀I₁I₂/(2πd).", "misconception": "Confusing 2π (Biot-Savart for infinite wire) with 4π (Coulomb''s law constant)"}, {"option_key": "C", "hint": "The distance d appears to the first power, not squared. This is not an inverse-square law like Coulomb''s law.", "misconception": "Incorrectly applying inverse-square law to magnetic force between wires"}, {"option_key": "D", "hint": "Having d in the numerator would mean force increases with distance, which is physically incorrect. Force decreases as conductors are moved apart.", "misconception": "Placing d in the wrong part of the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An alpha particle (charge 2e, mass 4mₚ) and a proton (charge e, mass mₚ) are accelerated from rest through the same potential difference and then enter a uniform magnetic field perpendicular to their velocity. The ratio of the radii of their circular paths (rα/rₚ) is:", "explanation": "After acceleration through potential difference V, kinetic energy K = qV. So Kα = 2eV and Kₚ = eV. The radius of circular motion is r = √(2mK)/(qB). For alpha particle: rα = √(2 × 4mₚ × 2eV)/(2eB) = √(16mₚeV)/(2eB) = 4√(mₚeV)/(2eB). For proton: rₚ = √(2mₚeV)/(eB) = √(2mₚeV)/(eB). Therefore rα/rₚ = [4√(mₚeV)/(2eB)] / [√(2mₚeV)/(eB)] = [4/(2)] × [1/√2] = 2/√2 = √2 = 1:1 × √2. So rα/rₚ = √2.", "correct_answer": "C", "concept_tags": ["alpha-particle", "proton", "radius-ratio", "potential-difference", "circular-motion"], "payload": {"question_id": "cuet-phy-magmov-force-11", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "1:1", "is_correct": false}, {"key": "B", "text": "2:1", "is_correct": false}, {"key": "C", "text": "√2 : 1", "is_correct": true}, {"key": "D", "text": "1 : √2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1:1 would require identical r values. Since the alpha particle has different mass and charge, r = √(2mK)/(qB) with K = qV gives different radii.", "misconception": "Assuming equal radii for particles accelerated through same potential"}, {"option_key": "B", "hint": "2:1 would result from r ∝ m/q without properly accounting for the velocity gained through the potential difference.", "misconception": "Not correctly relating kinetic energy to the potential difference for different charges"}, {"option_key": "D", "hint": "1:√2 is the inverse of the correct ratio. The alpha particle, with greater momentum, has the larger radius.", "misconception": "Inverting the ratio of radii"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of length L is bent into a semicircular loop and carries a current I. It is placed in a uniform magnetic field B directed perpendicular to the plane of the loop. The net force on the semicircular wire is:", "explanation": "For a curved wire in a uniform magnetic field, the net force equals the force on a straight wire connecting the two ends of the curve. The semicircular wire of length L has radius r = L/π. The straight-line distance between the two ends (the diameter) is 2r = 2L/π. Therefore, the net force is F = BI × (2L/π) = 2BIL/π. The direction follows from F = IL × B for the equivalent straight conductor.", "correct_answer": "A", "concept_tags": ["semicircular-loop", "net-force", "uniform-field", "equivalent-straight-wire"], "payload": {"question_id": "cuet-phy-magmov-force-12", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "2BIL/π", "is_correct": true}, {"key": "B", "text": "BIL", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "πBIL", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "BIL would be the force if the entire wire length L were straight and perpendicular to B. But for a semicircle, the effective length is the chord (diameter) = 2L/π.", "misconception": "Using the arc length instead of the chord length for net force"}, {"option_key": "C", "hint": "Zero net force applies to a complete closed loop in a uniform field. A semicircle is not a closed loop, so the net force is not zero.", "misconception": "Confusing semicircular wire with a complete loop"}, {"option_key": "D", "hint": "πBIL greatly overestimates the force. The effective straight-line length is 2L/π, which is shorter than L, not longer.", "misconception": "Using an incorrect geometric relationship"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The kinetic energy of a charged particle moving in a uniform magnetic field remains constant.\nReason (R): The magnetic force on a moving charge is always perpendicular to its velocity.", "explanation": "The assertion is correct: since the magnetic force does no work, the kinetic energy (and hence the speed) of the charged particle remains unchanged. The reason is also correct: F = qv × B is always perpendicular to v by the nature of the cross product. Furthermore, the reason correctly explains the assertion — it is precisely because the force is perpendicular to velocity that no work is done (W = F · ds = 0 when F ⊥ v), and therefore kinetic energy is conserved.", "correct_answer": "A", "concept_tags": ["kinetic-energy", "magnetic-force", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-magmov-force-13", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A. The perpendicularity of F to v means W = F · v dt = 0, so KE is constant. The causal link is direct.", "misconception": "Failing to see the direct causal connection between perpendicular force and zero work"}, {"option_key": "C", "hint": "The reason is a fundamental property of the cross product (v × B is always perpendicular to v). R is definitely correct.", "misconception": "Doubting the perpendicularity of the magnetic force to velocity"}, {"option_key": "D", "hint": "The assertion is correct — speed and hence KE of a charged particle in a magnetic field do not change. This is experimentally verified.", "misconception": "Thinking magnetic field changes the kinetic energy of a charge"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A current-carrying closed loop placed in a uniform magnetic field experiences a net force of zero.\nReason (R): The force on a current-carrying conductor in a magnetic field is given by F = I(L × B), where L is the length vector of the conductor.", "explanation": "The assertion is correct: for a closed loop in a uniform magnetic field, the net force is the vector sum of forces on all elements, which equals I(∮dL) × B = I × 0 × B = 0, since the line integral of dL around a closed loop is zero. The reason is also correct: F = I(L × B) is indeed the expression for force on a straight current-carrying conductor. However, the reason by itself does not directly explain why the net force on a closed loop is zero — one also needs the fact that ∮dL = 0 for a closed loop in a uniform field. So R is not the complete explanation of A.", "correct_answer": "B", "concept_tags": ["closed-loop", "net-force-zero", "uniform-field", "force-on-conductor"], "payload": {"question_id": "cuet-phy-magmov-force-14", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are correct, R only gives the force formula for a conductor. It does not explain why the sum of all such forces on a closed loop is zero. The explanation requires ∮dL = 0.", "misconception": "Assuming the force formula alone explains the zero net force on a closed loop"}, {"option_key": "C", "hint": "R is indeed correct. F = I(L × B) is the standard expression for force on a current-carrying conductor in a uniform field.", "misconception": "Doubting the validity of the force formula"}, {"option_key": "D", "hint": "A is correct. A closed current loop in a uniform magnetic field has zero net force (though it may experience a torque).", "misconception": "Confusing torque with net force on a loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Charged particle moving parallel to B\n(Q) Charged particle moving perpendicular to B\n(R) Charged particle moving at angle θ (0° < θ < 90°) to B\n(S) Charged particle at rest in B\n\nColumn II:\n(1) Helical path\n(2) Circular path\n(3) Straight line (no force)\n(4) No motion", "explanation": "P → 3: When velocity is parallel to B, sinθ = 0, so F = 0 and the particle continues in a straight line. Q → 2: When velocity is perpendicular to B, the constant perpendicular force causes circular motion. R → 1: When velocity has both parallel and perpendicular components to B, the perpendicular component causes circular motion while the parallel component causes linear drift, resulting in a helical path. S → 4: A stationary charge (v = 0) experiences no magnetic force and remains at rest.", "correct_answer": "D", "concept_tags": ["motion-in-magnetic-field", "circular-motion", "helical-motion", "match-the-following"], "payload": {"question_id": "cuet-phy-magmov-force-15", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}, {"key": "B", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→1, S→4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "P→2 is wrong. A particle moving parallel to B experiences zero force and moves in a straight line, not a circle.", "misconception": "Confusing parallel and perpendicular motion in B"}, {"option_key": "B", "hint": "Q→1 is wrong. A particle moving perpendicular to B traces a circle, not a helix. A helix requires a velocity component along B.", "misconception": "Confusing circular and helical paths"}, {"option_key": "C", "hint": "P→4 is wrong. A particle moving parallel to B is not stationary — it continues in a straight line since there is no magnetic force.", "misconception": "Thinking no force means no motion"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) SI unit of magnetic field\n(Q) Force between two parallel conductors carrying 1 A each, separated by 1 m, per unit length\n(R) Radius of circular path of charge q, mass m, speed v in field B\n(S) Condition for a charged particle to pass undeflected through crossed E and B fields\n\nColumn II:\n(1) mv/(qB)\n(2) 2 × 10⁻⁷ N/m\n(3) v = E/B\n(4) Tesla (T)", "explanation": "P → 4: The SI unit of magnetic field is Tesla (T). Q → 2: Using F/L = μ₀I₁I₂/(2πd) with I₁ = I₂ = 1 A, d = 1 m: F/L = (4π × 10⁻⁷ × 1 × 1)/(2π × 1) = 2 × 10⁻⁷ N/m. This is the basis for the definition of the ampere. R → 1: The radius of circular motion is r = mv/(qB), obtained by equating qvB = mv²/r. S → 3: In a velocity selector, qE = qvB gives v = E/B.", "correct_answer": "C", "concept_tags": ["tesla", "ampere-definition", "radius-formula", "velocity-selector", "match-the-following"], "payload": {"question_id": "cuet-phy-magmov-force-16", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→4, Q→1, R→2, S→3", "is_correct": false}, {"key": "B", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": true}, {"key": "D", "text": "P→2, Q→4, R→1, S→3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q→1 is wrong. The force per unit length between two wires is a numerical value (2 × 10⁻⁷ N/m), not the expression mv/(qB) which gives the radius of circular motion.", "misconception": "Mixing up the radius formula with the force between parallel conductors"}, {"option_key": "B", "hint": "R→3 is wrong. The radius of circular path is r = mv/(qB), not v = E/B. The condition v = E/B applies to velocity selectors.", "misconception": "Confusing the radius formula with the velocity selector condition"}, {"option_key": "D", "hint": "P→2 is wrong. The SI unit of magnetic field is Tesla (4), not 2 × 10⁻⁷ N/m (which is the force per unit length between parallel conductors).", "misconception": "Confusing the unit of B with the force value used in defining the ampere"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The direction of force on a current-carrying conductor placed in a magnetic field can be determined using Fleming''s left-hand rule.", "explanation": "This statement is TRUE. Fleming''s left-hand rule states: if the forefinger points in the direction of the magnetic field (B), the middle finger points in the direction of current (I), then the thumb gives the direction of force (F) on the conductor. This rule is specifically used for determining the direction of force on a current-carrying conductor in a magnetic field (motor rule).", "correct_answer": "A", "concept_tags": ["flemings-left-hand-rule", "direction-of-force", "current-carrying-conductor"], "payload": {"question_id": "cuet-phy-magmov-force-17", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Fleming''s left-hand rule is the standard rule for finding the direction of force on a current-carrying conductor in a magnetic field. It is widely used and correct.", "misconception": "Confusing Fleming''s left-hand rule (motor rule) with Fleming''s right-hand rule (generator/dynamo rule)"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A magnetic field can change the speed of a charged particle moving through it.", "explanation": "This statement is FALSE. The magnetic force on a charged particle is F = qv × B, which is always perpendicular to the velocity. A perpendicular force changes only the direction of velocity, not its magnitude (speed). Since no work is done by the magnetic force (W = F · ds = 0 when F ⊥ ds), the kinetic energy and hence the speed remain constant.", "correct_answer": "B", "concept_tags": ["magnetic-force", "speed-constant", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-magmov-force-18", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic force is always perpendicular to velocity and does zero work. Since work-energy theorem gives ΔKE = W = 0, speed cannot change.", "misconception": "Assuming any force acting on a particle changes its speed"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "One ampere is defined as that steady current which, when flowing through each of two infinitely long, straight, parallel conductors placed 1 m apart in vacuum, produces a force per unit length of _____ N/m between them.", "explanation": "The SI definition of one ampere is based on the force between two parallel current-carrying conductors. Using F/L = μ₀I₁I₂/(2πd), with I₁ = I₂ = 1 A and d = 1 m: F/L = (4π × 10⁻⁷ × 1 × 1)/(2π × 1) = 2 × 10⁻⁷ N/m. This value defines the ampere in the SI system.", "correct_answer": "D", "concept_tags": ["ampere-definition", "parallel-conductors", "force-per-unit-length", "SI-units"], "payload": {"question_id": "cuet-phy-magmov-force-19", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "4π × 10⁻⁷", "is_correct": false}, {"key": "B", "text": "1 × 10⁻⁷", "is_correct": false}, {"key": "C", "text": "4 × 10⁻⁷", "is_correct": false}, {"key": "D", "text": "2 × 10⁻⁷", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4π × 10⁻⁷ is the value of μ₀ (permeability of free space), not the force per unit length. F/L = μ₀I₁I₂/(2πd) = μ₀/(2π) = 2 × 10⁻⁷ N/m.", "misconception": "Confusing μ₀ with the force per unit length"}, {"option_key": "B", "hint": "1 × 10⁻⁷ is half the correct value. The calculation gives μ₀/(2π) = 4π × 10⁻⁷/(2π) = 2 × 10⁻⁷, not 1 × 10⁻⁷.", "misconception": "Arithmetic error in simplifying μ₀/(2π)"}, {"option_key": "C", "hint": "4 × 10⁻⁷ is twice the correct value. Carefully simplify: 4π × 10⁻⁷/(2π) = 2 × 10⁻⁷.", "misconception": "Cancellation error when dividing 4π by 2π"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a mass spectrometer, singly ionized ions of two isotopes of an element (masses m₁ = 20 u and m₂ = 22 u, where 1 u = 1.66 × 10⁻²⁷ kg) are accelerated through a potential difference of 10 kV and then enter a uniform magnetic field of 0.2 T perpendicular to their velocity. The ions travel in semicircular paths and strike a photographic plate. What is the separation between the two lines formed on the photographic plate?", "explanation": "After acceleration, KE = qV, so v = √(2qV/m). The radius of the semicircular path is r = mv/(qB) = (m/(qB))√(2qV/m) = √(2mV/q)/B. The separation on the plate equals the difference in diameters: Δx = 2r₂ − 2r₁ = (2/B)√(2V/q)(√m₂ − √m₁). With q = 1.6 × 10⁻¹⁹ C, V = 10⁴ V, B = 0.2 T: √(2V/q) = √(2 × 10⁴/(1.6 × 10⁻¹⁹)) = √(1.25 × 10²³) = 1.118 × 10¹¹·⁵. Computing: r = √(2mV/q)/B. For m₁ = 20 × 1.66 × 10⁻²⁷ = 3.32 × 10⁻²⁶ kg: r₁ = √(2 × 3.32 × 10⁻²⁶ × 10⁴/1.6 × 10⁻¹⁹)/0.2 = √(4.15 × 10⁻³)/0.2 = 0.0644/0.2 = 0.322 m. For m₂ = 22 × 1.66 × 10⁻²⁷ = 3.652 × 10⁻²⁶ kg: r₂ = √(2 × 3.652 × 10⁻²⁶ × 10⁴/1.6 × 10⁻¹⁹)/0.2 = √(4.565 × 10⁻³)/0.2 = 0.0676/0.2 = 0.338 m. Separation = 2(r₂ − r₁) = 2(0.338 − 0.322) = 2 × 0.016 = 0.032 m ≈ 3.2 cm.", "correct_answer": "B", "concept_tags": ["mass-spectrometer", "isotopes", "semicircular-path", "separation", "scenario-based"], "payload": {"question_id": "cuet-phy-magmov-force-20", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6 cm", "is_correct": false}, {"key": "B", "text": "3.2 cm", "is_correct": true}, {"key": "C", "text": "6.4 cm", "is_correct": false}, {"key": "D", "text": "0.8 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.6 cm is the difference in radii (r₂ − r₁), not diameters. The separation on the photographic plate equals the difference in diameters: 2(r₂ − r₁).", "misconception": "Forgetting to multiply the radius difference by 2 for the diameter difference"}, {"option_key": "C", "hint": "6.4 cm is double the correct answer. Check that you are not multiplying by 4 instead of 2 when converting from radius to diameter difference.", "misconception": "Doubling the diameter difference instead of the radius difference"}, {"option_key": "D", "hint": "0.8 cm is too small. This may result from an error in the calculation of radii or forgetting to use the correct mass values.", "misconception": "Arithmetic error in computing the radii"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnifying power of a simple microscope is given by:", "explanation": "A simple microscope (magnifying glass) is a convex lens of short focal length. Its magnifying power when the final image is at the least distance of distinct vision (D = 25 cm) is M = 1 + D/f. This formula assumes the image is formed at the near point.", "correct_answer": "B", "concept_tags": ["simple-microscope", "magnifying-power", "convex-lens"], "payload": {"question_id": "cuet-phy-ray-instruments-01", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "M = D/f", "is_correct": false}, {"key": "B", "text": "M = 1 + D/f", "is_correct": true}, {"key": "C", "text": "M = f/D", "is_correct": false}, {"key": "D", "text": "M = 1 + f/D", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "M = D/f gives the magnifying power when the image is at infinity (relaxed eye), not at the near point.", "misconception": "Confusing the formula for image at infinity with image at near point"}, {"option_key": "C", "hint": "M = f/D would give a value less than 1 for typical lenses (f < D), which contradicts the purpose of magnification.", "misconception": "Inverting the D/f ratio"}, {"option_key": "D", "hint": "M = 1 + f/D incorrectly swaps f and D. The correct formula has D in the numerator since D > f for useful magnification.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The near point of a normal human eye is at a distance of:", "explanation": "The near point (least distance of distinct vision) of a normal healthy eye is 25 cm. This is the closest distance at which the eye can focus on an object comfortably. The far point of a normal eye is at infinity.", "correct_answer": "C", "concept_tags": ["near-point", "human-eye", "least-distance-of-distinct-vision"], "payload": {"question_id": "cuet-phy-ray-instruments-02", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "10 cm", "is_correct": false}, {"key": "B", "text": "15 cm", "is_correct": false}, {"key": "C", "text": "25 cm", "is_correct": true}, {"key": "D", "text": "50 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 cm is too close for the normal eye to focus. A person who can see clearly at 10 cm would have an abnormally high accommodation.", "misconception": null}, {"option_key": "B", "hint": "15 cm is less than the standard near point of 25 cm for a normal eye.", "misconception": null}, {"option_key": "D", "hint": "50 cm would be the near point of a person with presbyopia or hypermetropia, not a normal eye.", "misconception": "Confusing normal near point with that of a defective eye"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Myopia (short-sightedness) can be corrected by using a:", "explanation": "In myopia, the eye can see near objects clearly but distant objects appear blurred because the image is formed in front of the retina. A concave (diverging) lens of appropriate focal length diverges the incoming rays before they enter the eye, so the image shifts back to the retina.", "correct_answer": "A", "concept_tags": ["myopia", "concave-lens", "defects-of-vision", "correction"], "payload": {"question_id": "cuet-phy-ray-instruments-03", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "Concave lens", "is_correct": true}, {"key": "B", "text": "Convex lens", "is_correct": false}, {"key": "C", "text": "Cylindrical lens", "is_correct": false}, {"key": "D", "text": "Bifocal lens", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A convex lens converges light further, which would worsen myopia. Convex lenses are used to correct hypermetropia.", "misconception": "Confusing the corrective lens for myopia and hypermetropia"}, {"option_key": "C", "hint": "Cylindrical lenses are used to correct astigmatism, not myopia.", "misconception": "Confusing correction for astigmatism with myopia"}, {"option_key": "D", "hint": "Bifocal lenses are used for presbyopia, where both near and far vision need correction, not for simple myopia.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of power of a lens is:", "explanation": "The power of a lens is defined as P = 1/f, where f is the focal length in metres. The SI unit of lens power is the dioptre (D), where 1 D = 1 m⁻¹.", "correct_answer": "D", "concept_tags": ["power-of-lens", "dioptre", "SI-unit"], "payload": {"question_id": "cuet-phy-ray-instruments-04", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "Metre", "is_correct": false}, {"key": "B", "text": "Watt", "is_correct": false}, {"key": "C", "text": "Centimetre", "is_correct": false}, {"key": "D", "text": "Dioptre", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Metre is the unit of focal length, not power. Power is the reciprocal of focal length.", "misconception": "Confusing focal length unit with power unit"}, {"option_key": "B", "hint": "Watt is the unit of power in mechanics/electricity (energy per unit time), not optical power.", "misconception": "Confusing optical power with mechanical/electrical power"}, {"option_key": "C", "hint": "Centimetre is a unit of length and is not used as the unit of lens power.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b13');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnifying power of an astronomical telescope in normal adjustment is 20. If the focal length of the objective is 100 cm, the focal length of the eyepiece is:", "explanation": "For an astronomical telescope in normal adjustment (image at infinity), the magnifying power M = fₒ/fₑ. Given M = 20 and fₒ = 100 cm: 20 = 100/fₑ, so fₑ = 100/20 = 5 cm.", "correct_answer": "B", "concept_tags": ["astronomical-telescope", "magnifying-power", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-05", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "2 cm", "is_correct": false}, {"key": "B", "text": "5 cm", "is_correct": true}, {"key": "C", "text": "10 cm", "is_correct": false}, {"key": "D", "text": "20 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "fₑ = 2 cm would give M = 100/2 = 50, not 20.", "misconception": null}, {"option_key": "C", "hint": "fₑ = 10 cm would give M = 100/10 = 10, not 20.", "misconception": null}, {"option_key": "D", "hint": "fₑ = 20 cm would give M = 100/20 = 5, not 20. Do not confuse the magnification value with the focal length.", "misconception": "Confusing the magnifying power value with the eyepiece focal length"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A compound microscope consists of an objective of focal length 1 cm and an eyepiece of focal length 5 cm. If the length of the tube is 20 cm and the image is formed at the least distance of distinct vision (25 cm), the magnifying power is approximately:", "explanation": "For a compound microscope, M = (L/fₒ) × (1 + D/fₑ), where L is the image distance from the objective (approximately the tube length minus fₑ for rough calculation). More precisely, L ≈ 20 − 5 = 15 cm (separation between objective image and eyepiece). So M = (15/1) × (1 + 25/5) = 15 × 6 = 90. The magnifying power is approximately 90.", "correct_answer": "C", "concept_tags": ["compound-microscope", "magnifying-power", "objective", "eyepiece"], "payload": {"question_id": "cuet-phy-ray-instruments-06", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "30", "is_correct": false}, {"key": "B", "text": "60", "is_correct": false}, {"key": "C", "text": "90", "is_correct": true}, {"key": "D", "text": "120", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30 would result from using M = L/fₒ × D/fₑ without the +1 term and with incorrect L.", "misconception": null}, {"option_key": "B", "hint": "60 results from using L = 20 cm directly instead of subtracting fₑ to get the image distance from the objective.", "misconception": "Using total tube length instead of image distance from objective"}, {"option_key": "D", "hint": "120 would require L/fₒ = 20, implying L = 20 cm without subtracting fₑ, combined with the full eyepiece magnification.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The length of an astronomical telescope in normal adjustment is 105 cm. If the magnifying power is 20, the focal lengths of the objective and eyepiece are:", "explanation": "In normal adjustment, the tube length L = fₒ + fₑ = 105 cm and M = fₒ/fₑ = 20. From M: fₒ = 20fₑ. Substituting: 20fₑ + fₑ = 105, so 21fₑ = 105, giving fₑ = 5 cm and fₒ = 100 cm.", "correct_answer": "A", "concept_tags": ["astronomical-telescope", "tube-length", "magnifying-power", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-07", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "fₒ = 100 cm, fₑ = 5 cm", "is_correct": true}, {"key": "B", "text": "fₒ = 95 cm, fₑ = 10 cm", "is_correct": false}, {"key": "C", "text": "fₒ = 84 cm, fₑ = 21 cm", "is_correct": false}, {"key": "D", "text": "fₒ = 105 cm, fₑ = 5.25 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "fₒ + fₑ = 95 + 10 = 105 cm (correct sum), but fₒ/fₑ = 95/10 = 9.5, not 20.", "misconception": null}, {"option_key": "C", "hint": "fₒ + fₑ = 84 + 21 = 105 cm (correct sum), but fₒ/fₑ = 84/21 = 4, not 20.", "misconception": null}, {"option_key": "D", "hint": "fₒ + fₑ = 105 + 5.25 = 110.25 cm, which does not equal the tube length of 105 cm.", "misconception": "Ignoring the constraint that fₒ + fₑ = L"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A person with hypermetropia has a near point at 75 cm. The power of the corrective lens required to bring the near point to the normal position (25 cm) is:", "explanation": "The corrective lens must form a virtual image at 75 cm (the defective near point) of an object placed at 25 cm (the normal near point). Using the thin lens formula: 1/f = 1/v − 1/u = 1/(−75) − 1/(−25) = −1/75 + 1/25 = (−1 + 3)/75 = 2/75. So f = 75/2 = 37.5 cm = 0.375 m. Power P = 1/f = 1/0.375 ≈ +2.67 D.", "correct_answer": "D", "concept_tags": ["hypermetropia", "corrective-lens", "power-of-lens", "lens-formula"], "payload": {"question_id": "cuet-phy-ray-instruments-08", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "+1.33 D", "is_correct": false}, {"key": "B", "text": "−2.67 D", "is_correct": false}, {"key": "C", "text": "+4.0 D", "is_correct": false}, {"key": "D", "text": "+2.67 D", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "+1.33 D corresponds to f = 75 cm, which would result from using P = 1/v only, without applying the full lens formula.", "misconception": null}, {"option_key": "B", "hint": "A negative power (concave lens) would further diverge light, making hypermetropia worse. Correction requires a converging (positive) lens.", "misconception": "Using a concave lens for hypermetropia"}, {"option_key": "C", "hint": "+4.0 D corresponds to f = 25 cm. This would result from using only the object distance, ignoring the image distance constraint.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A convex lens of focal length 10 cm is used as a magnifying glass. The maximum magnifying power when the image is formed at the least distance of distinct vision is:", "explanation": "The magnifying power of a simple microscope with the image at the near point is M = 1 + D/f = 1 + 25/10 = 1 + 2.5 = 3.5. This is the maximum magnifying power achievable with this lens.", "correct_answer": "C", "concept_tags": ["simple-microscope", "magnifying-power", "near-point"], "payload": {"question_id": "cuet-phy-ray-instruments-09", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "2.5", "is_correct": false}, {"key": "B", "text": "3.0", "is_correct": false}, {"key": "C", "text": "3.5", "is_correct": true}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2.5 = D/f, which is the magnifying power when the image is at infinity, not at the near point.", "misconception": "Using M = D/f instead of M = 1 + D/f for near point image"}, {"option_key": "B", "hint": "3.0 does not correspond to any standard formula for this configuration.", "misconception": null}, {"option_key": "D", "hint": "10 is the focal length in cm, not the magnifying power. M = 1 + D/f, not f itself.", "misconception": "Confusing focal length with magnifying power"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The accommodation of the human eye refers to the ability of the eye to:", "explanation": "Accommodation is the ability of the eye lens to change its focal length by altering its curvature through the action of ciliary muscles. When viewing near objects, the ciliary muscles contract, making the lens thicker and decreasing its focal length. For distant objects, the muscles relax, making the lens thinner and increasing the focal length.", "correct_answer": "B", "concept_tags": ["accommodation", "human-eye", "ciliary-muscles", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-10", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "Change the size of the pupil", "is_correct": false}, {"key": "B", "text": "Adjust the focal length of the eye lens", "is_correct": true}, {"key": "C", "text": "Change the distance between the lens and retina", "is_correct": false}, {"key": "D", "text": "Change the refractive index of the eye lens", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Changing pupil size controls the amount of light entering the eye (like an aperture), not the focusing ability.", "misconception": "Confusing pupil adjustment with accommodation"}, {"option_key": "C", "hint": "In the human eye, the distance between the lens and retina is fixed. The eye focuses by changing the lens curvature, not by moving the lens.", "misconception": "Applying camera focusing mechanism to the human eye"}, {"option_key": "D", "hint": "The refractive index of the eye lens material does not change during accommodation; only its curvature changes.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A Galilean telescope has an objective of focal length 30 cm and an eyepiece of focal length 6 cm. For a normal adjustment, the magnifying power and the length of the telescope are:", "explanation": "A Galilean telescope uses a concave lens as the eyepiece. The magnifying power M = fₒ/fₑ = 30/6 = 5. The length of the telescope in normal adjustment is L = fₒ − fₑ = 30 − 6 = 24 cm (since the eyepiece is a diverging lens placed inside the focal point of the objective).", "correct_answer": "D", "concept_tags": ["galilean-telescope", "magnifying-power", "tube-length", "concave-eyepiece"], "payload": {"question_id": "cuet-phy-ray-instruments-11", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "analyze", "options": [{"key": "A", "text": "M = 5, L = 36 cm", "is_correct": false}, {"key": "B", "text": "M = 6, L = 24 cm", "is_correct": false}, {"key": "C", "text": "M = 5, L = 30 cm", "is_correct": false}, {"key": "D", "text": "M = 5, L = 24 cm", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "L = 36 cm = fₒ + fₑ is the tube length for an astronomical telescope (with a convex eyepiece), not a Galilean telescope.", "misconception": "Using L = fₒ + fₑ for a Galilean telescope instead of L = fₒ − fₑ"}, {"option_key": "B", "hint": "M = 6 would require fₒ/fₑ = 6, but 30/6 = 5, not 6.", "misconception": null}, {"option_key": "C", "hint": "L = 30 cm equals fₒ alone. The tube length of a Galilean telescope is fₒ − fₑ, not just fₒ.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A reflecting telescope uses a concave mirror of focal length 100 cm as its objective. If the magnifying power is 50 and the final image is at infinity, the focal length of the eyepiece is:", "explanation": "For a reflecting telescope with the final image at infinity, the magnifying power M = fₒ/fₑ, same as for a refracting telescope. Given M = 50 and fₒ = 100 cm: fₑ = fₒ/M = 100/50 = 2 cm.", "correct_answer": "A", "concept_tags": ["reflecting-telescope", "magnifying-power", "concave-mirror", "eyepiece"], "payload": {"question_id": "cuet-phy-ray-instruments-12", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "analyze", "options": [{"key": "A", "text": "2 cm", "is_correct": true}, {"key": "B", "text": "5 cm", "is_correct": false}, {"key": "C", "text": "50 cm", "is_correct": false}, {"key": "D", "text": "0.5 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "fₑ = 5 cm gives M = 100/5 = 20, not 50.", "misconception": null}, {"option_key": "C", "hint": "fₑ = 50 cm gives M = 100/50 = 2, not 50. This confuses the magnification value with the focal length.", "misconception": "Confusing magnifying power with eyepiece focal length"}, {"option_key": "D", "hint": "fₑ = 0.5 cm gives M = 100/0.5 = 200, which is much larger than 50.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): In an astronomical telescope, the objective has a large focal length and the eyepiece has a small focal length.\nReason (R): The magnifying power of an astronomical telescope in normal adjustment is M = fₒ/fₑ.", "explanation": "Both A and R are correct. The magnifying power M = fₒ/fₑ shows that to achieve high magnification, fₒ should be large and fₑ should be small. The reason directly explains why the objective has a large focal length and the eyepiece a small one, so R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["astronomical-telescope", "magnifying-power", "objective", "eyepiece"], "payload": {"question_id": "cuet-phy-ray-instruments-13", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: the formula M = fₒ/fₑ shows that large fₒ and small fₑ maximise magnification.", "misconception": null}, {"option_key": "C", "hint": "R is the standard and correct formula for the magnifying power of an astronomical telescope in normal adjustment.", "misconception": null}, {"option_key": "D", "hint": "A is correct; any standard astronomical telescope is designed with a long focal length objective and a short focal length eyepiece.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A reflecting telescope is preferred over a refracting telescope for large aperture instruments.\nReason (R): Large lenses suffer from chromatic aberration and are difficult to manufacture without sagging, whereas large mirrors do not have chromatic aberration and can be supported from behind.", "explanation": "Both A and R are correct, and R is the correct explanation of A. Large aperture refracting telescopes suffer from chromatic aberration (since lenses disperse light) and mechanical issues like sagging due to gravity. Reflecting telescopes use mirrors, which have no chromatic aberration and can be supported from behind to prevent sagging. These are the primary reasons why reflecting telescopes are preferred for large instruments.", "correct_answer": "A", "concept_tags": ["reflecting-telescope", "refracting-telescope", "chromatic-aberration", "advantages"], "payload": {"question_id": "cuet-phy-ray-instruments-14", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly addresses the advantages of mirrors over lenses for large apertures, which is exactly why reflecting telescopes are preferred. R explains A.", "misconception": null}, {"option_key": "C", "hint": "R is factually correct — large lenses do suffer from chromatic aberration and sagging, and mirrors avoid both issues.", "misconception": null}, {"option_key": "D", "hint": "A is correct; all major astronomical observatories use reflecting telescopes for their large instruments.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the eye defects in Column I with their corrective lenses in Column II:\n\nColumn I:\nA. Myopia\nB. Hypermetropia\nC. Astigmatism\nD. Presbyopia\n\nColumn II:\n1. Bifocal lens\n2. Cylindrical lens\n3. Concave lens\n4. Convex lens", "explanation": "Myopia is corrected using a concave lens to diverge light (A-3). Hypermetropia is corrected using a convex lens to converge light (B-4). Astigmatism, caused by a non-spherical cornea, is corrected using a cylindrical lens (C-2). Presbyopia, affecting both near and far vision in old age, is corrected using bifocal lenses (D-1).", "correct_answer": "B", "concept_tags": ["myopia", "hypermetropia", "astigmatism", "presbyopia", "corrective-lens"], "payload": {"question_id": "cuet-phy-ray-instruments-15", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-2, D-1", "is_correct": true}, {"key": "C", "text": "A-3, B-4, C-1, D-2", "is_correct": false}, {"key": "D", "text": "A-2, B-1, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps the corrective lenses for myopia and hypermetropia. Myopia requires a concave (diverging) lens, not convex.", "misconception": "Interchanging corrective lenses for myopia and hypermetropia"}, {"option_key": "C", "hint": "This swaps astigmatism and presbyopia corrections. Astigmatism uses cylindrical lenses (2), not bifocal (1).", "misconception": null}, {"option_key": "D", "hint": "This assigns completely incorrect lenses to all defects and has no basis in optics.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the optical instruments in Column I with the correct expression for their magnifying power in Column II:\n\nColumn I:\nA. Simple microscope (image at near point)\nB. Astronomical telescope (normal adjustment)\nC. Compound microscope (image at infinity)\nD. Galilean telescope (normal adjustment)\n\nColumn II:\n1. fₒ/fₑ\n2. (L/fₒ)(D/fₑ)\n3. 1 + D/f\n4. fₒ/fₑ (erect image)", "explanation": "A simple microscope with image at the near point has M = 1 + D/f (A-3). An astronomical telescope in normal adjustment has M = fₒ/fₑ (B-1). A compound microscope with image at infinity has M = (L/fₒ)(D/fₑ) where L is the tube length (C-2). A Galilean telescope in normal adjustment also has M = fₒ/fₑ but produces an erect image (D-4).", "correct_answer": "C", "concept_tags": ["magnifying-power", "simple-microscope", "compound-microscope", "astronomical-telescope", "galilean-telescope"], "payload": {"question_id": "cuet-phy-ray-instruments-16", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "C", "text": "A-3, B-1, C-2, D-4", "is_correct": true}, {"key": "D", "text": "A-1, B-3, C-4, D-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and D. The astronomical telescope (B) matches fₒ/fₑ (1), while the Galilean telescope (D) matches fₒ/fₑ with erect image (4).", "misconception": null}, {"option_key": "B", "hint": "A-2 assigns the compound microscope formula to the simple microscope, which is incorrect. The simple microscope uses M = 1 + D/f.", "misconception": "Confusing simple and compound microscope formulas"}, {"option_key": "D", "hint": "This assigns completely incorrect formulas to all instruments. The simple microscope does not use M = fₒ/fₑ.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnifying power of an astronomical telescope increases if the focal length of the objective is increased.", "explanation": "This statement is true. The magnifying power of an astronomical telescope in normal adjustment is M = fₒ/fₑ. If fₒ (focal length of the objective) increases while fₑ remains constant, the magnifying power increases proportionally.", "correct_answer": "A", "concept_tags": ["astronomical-telescope", "magnifying-power", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-17", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Since M = fₒ/fₑ, increasing fₒ directly increases M. The statement is therefore true.", "misconception": "Thinking magnifying power decreases with larger objective focal length"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A person suffering from myopia can see distant objects clearly without any corrective lens.", "explanation": "This statement is false. Myopia (short-sightedness) means the person can see nearby objects clearly but distant objects appear blurred. The far point of a myopic eye is at a finite distance (not at infinity). A concave lens is needed to see distant objects clearly.", "correct_answer": "B", "concept_tags": ["myopia", "defects-of-vision", "far-point"], "payload": {"question_id": "cuet-phy-ray-instruments-18", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Myopia specifically means inability to see distant objects clearly. The image of distant objects falls in front of the retina.", "misconception": "Confusing myopia with normal vision or hypermetropia"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The power of a concave lens of focal length 50 cm is _____ dioptre.", "explanation": "The power of a lens is P = 1/f, where f is in metres. For a concave (diverging) lens, the focal length is negative: f = −50 cm = −0.50 m. Therefore P = 1/(−0.50) = −2 D. The negative sign indicates a diverging lens.", "correct_answer": "B", "concept_tags": ["power-of-lens", "concave-lens", "dioptre", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-19", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "+2", "is_correct": false}, {"key": "B", "text": "−2", "is_correct": true}, {"key": "C", "text": "−0.5", "is_correct": false}, {"key": "D", "text": "+50", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+2 D would be the power of a convex lens of focal length 50 cm. A concave lens has negative power.", "misconception": "Ignoring the sign convention for concave lens power"}, {"option_key": "C", "hint": "−0.5 would result from using P = −f (in metres) instead of P = 1/f.", "misconception": "Confusing focal length with power"}, {"option_key": "D", "hint": "+50 results from not converting cm to metres and ignoring the sign. P = 1/f where f must be in metres.", "misconception": "Forgetting to convert cm to metres and ignoring sign"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A biology student uses a compound microscope to observe a cell. The objective lens has a focal length of 0.5 cm and the eyepiece has a focal length of 6.25 cm. The object is placed at a distance of 0.55 cm from the objective. The final image is formed at the least distance of distinct vision (25 cm).\n\nWhat is the approximate magnifying power of the microscope?", "explanation": "First, find the image formed by the objective using 1/v − 1/u = 1/f: 1/v = 1/fₒ + 1/uₒ = 1/0.5 + 1/(−0.55) = 2 − 1.818 = 0.182, so v ≈ 5.5 cm. Magnification by objective: mₒ = v/u = 5.5/(−0.55) = −10. Magnification by eyepiece: mₑ = 1 + D/fₑ = 1 + 25/6.25 = 1 + 4 = 5. Total magnifying power M = mₒ × mₑ = −10 × 5 = −50. The magnitude is 50.", "correct_answer": "D", "concept_tags": ["compound-microscope", "magnifying-power", "objective", "eyepiece", "lens-formula"], "payload": {"question_id": "cuet-phy-ray-instruments-20", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "25", "is_correct": false}, {"key": "C", "text": "40", "is_correct": false}, {"key": "D", "text": "50", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10 is only the magnification produced by the objective alone. The total magnification includes the eyepiece contribution as well.", "misconception": "Ignoring the eyepiece magnification"}, {"option_key": "B", "hint": "25 does not correspond to any meaningful calculation. The eyepiece magnification alone is 5, not 25.", "misconception": null}, {"option_key": "C", "hint": "40 would result from using mₑ = D/fₑ = 4 instead of mₑ = 1 + D/fₑ = 5, missing the +1 term.", "misconception": "Using M = D/fₑ instead of M = 1 + D/fₑ for near-point image"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Total internal reflection can occur when light travels from:", "explanation": "Total internal reflection occurs only when light travels from a denser medium (higher refractive index) to a rarer medium (lower refractive index) and the angle of incidence exceeds the critical angle. It cannot occur when light goes from a rarer to a denser medium.", "correct_answer": "B", "concept_tags": ["total-internal-reflection", "denser-rarer-medium", "critical-angle"], "payload": {"question_id": "cuet-phy-ray-prism-01", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "A rarer medium to a denser medium", "is_correct": false}, {"key": "B", "text": "A denser medium to a rarer medium", "is_correct": true}, {"key": "C", "text": "Any medium to any other medium", "is_correct": false}, {"key": "D", "text": "Vacuum to any material medium", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "When light goes from rarer to denser medium, it bends towards the normal and can never reach the critical angle for TIR.", "misconception": "Reversing the condition for total internal reflection"}, {"option_key": "C", "hint": "TIR does not occur in all cases; it requires light to go from a denser to a rarer medium at an angle greater than the critical angle.", "misconception": null}, {"option_key": "D", "hint": "Vacuum has the lowest refractive index (n = 1), so light cannot go from vacuum to a material medium and undergo TIR.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The critical angle for a medium of refractive index √2 is:", "explanation": "The critical angle C is given by sin C = 1/n. For n = √2, sin C = 1/√2, which gives C = 45°. At this angle, the refracted ray grazes along the surface of separation.", "correct_answer": "C", "concept_tags": ["critical-angle", "refractive-index", "total-internal-reflection"], "payload": {"question_id": "cuet-phy-ray-prism-02", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "60°", "is_correct": false}, {"key": "C", "text": "45°", "is_correct": true}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "sin 30° = 0.5 = 1/2, which would correspond to n = 2, not √2.", "misconception": "Using wrong value of refractive index"}, {"option_key": "B", "hint": "sin 60° = √3/2 ≈ 0.866, which gives n = 2/√3 ≈ 1.155, not √2.", "misconception": null}, {"option_key": "D", "hint": "A critical angle of 90° would mean sin C = 1, giving n = 1, which corresponds to vacuum — not a medium with n = √2.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following phenomena is responsible for the formation of a mirage in deserts?", "explanation": "Mirages in deserts are caused by total internal reflection. The air near the hot ground is less dense (lower refractive index) than the cooler air above. Light from distant objects travelling downward through layers of progressively rarer air gets totally internally reflected, creating an illusion of water on the ground.", "correct_answer": "A", "concept_tags": ["mirage", "total-internal-reflection", "atmospheric-refraction"], "payload": {"question_id": "cuet-phy-ray-prism-03", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "Total internal reflection", "is_correct": true}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Interference", "is_correct": false}, {"key": "D", "text": "Polarisation", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Diffraction involves bending of light around obstacles and does not explain the inverted image seen in mirages.", "misconception": null}, {"option_key": "C", "hint": "Interference involves superposition of coherent light waves and produces fringe patterns, not mirage-like effects.", "misconception": null}, {"option_key": "D", "hint": "Polarisation deals with the orientation of the electric field vector and does not cause visual illusions like mirages.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the visible spectrum, which colour of light is deviated the most by a glass prism?", "explanation": "Violet light has the shortest wavelength among visible colours and hence the highest refractive index in glass. Since deviation increases with refractive index, violet light is deviated the most by a glass prism. Red light, having the longest wavelength, is deviated the least.", "correct_answer": "D", "concept_tags": ["dispersion", "prism", "deviation", "violet-light"], "payload": {"question_id": "cuet-phy-ray-prism-04", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "Red", "is_correct": false}, {"key": "B", "text": "Yellow", "is_correct": false}, {"key": "C", "text": "Green", "is_correct": false}, {"key": "D", "text": "Violet", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Red light has the longest wavelength and therefore the lowest refractive index in glass, resulting in the least deviation.", "misconception": "Confusing maximum and minimum deviation colours"}, {"option_key": "B", "hint": "Yellow lies in the middle of the visible spectrum and experiences moderate deviation, not the maximum.", "misconception": null}, {"option_key": "C", "hint": "Green, like yellow, is in the middle of the spectrum and does not experience the maximum deviation.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b13');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A ray of light passes through an equilateral prism such that the angle of incidence equals the angle of emergence and each equals 60°. The angle of minimum deviation is:", "explanation": "For an equilateral prism, A = 60°. At minimum deviation, i = e. Using the prism formula δ = i + e − A, we get δ_min = 60° + 60° − 60° = 60°. Also, at minimum deviation i = (A + δ_min)/2 = (60° + 60°)/2 = 60°, which is consistent.", "correct_answer": "B", "concept_tags": ["prism", "minimum-deviation", "equilateral-prism"], "payload": {"question_id": "cuet-phy-ray-prism-05", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "60°", "is_correct": true}, {"key": "C", "text": "45°", "is_correct": false}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30° would result if you incorrectly used δ = i − A/2 or some other wrong formula. The correct formula is δ = i + e − A.", "misconception": null}, {"option_key": "C", "hint": "45° does not follow from the prism formula with the given values of i, e, and A.", "misconception": null}, {"option_key": "D", "hint": "90° exceeds the angle of the prism and is far too large for this configuration.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Optical fibres work on the principle of:", "explanation": "Optical fibres use total internal reflection to transmit light signals over long distances with minimal loss. The fibre consists of a core with a higher refractive index surrounded by cladding with a lower refractive index, ensuring that light undergoes TIR repeatedly as it propagates through the fibre.", "correct_answer": "C", "concept_tags": ["optical-fibre", "total-internal-reflection", "applications"], "payload": {"question_id": "cuet-phy-ray-prism-06", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Refraction", "is_correct": false}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Total internal reflection", "is_correct": true}, {"key": "D", "text": "Scattering", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Simple refraction would cause light to exit the fibre at each boundary. TIR keeps the light confined within the core.", "misconception": "Confusing refraction with total internal reflection"}, {"option_key": "B", "hint": "Diffraction involves spreading of light around obstacles and has no role in guiding light through optical fibres.", "misconception": null}, {"option_key": "D", "hint": "Scattering disperses light in random directions and would cause signal loss, not signal transmission.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The refractive index of a prism material is √3 and the angle of the prism is 60°. The angle of minimum deviation is:", "explanation": "Using the prism formula: n = sin[(A + δ_min)/2] / sin(A/2). Substituting: √3 = sin[(60° + δ_min)/2] / sin 30° = sin[(60° + δ_min)/2] / 0.5. So sin[(60° + δ_min)/2] = √3/2, giving (60° + δ_min)/2 = 60°, hence δ_min = 60°.", "correct_answer": "A", "concept_tags": ["prism", "minimum-deviation", "refractive-index"], "payload": {"question_id": "cuet-phy-ray-prism-07", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "60°", "is_correct": true}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "30°", "is_correct": false}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Substituting δ_min = 45° gives sin(52.5°)/sin(30°) ≈ 0.793/0.5 = 1.586, which is not √3 ≈ 1.732.", "misconception": null}, {"option_key": "C", "hint": "Substituting δ_min = 30° gives sin(45°)/sin(30°) = (1/√2)/(1/2) = √2 ≈ 1.414, not √3.", "misconception": null}, {"option_key": "D", "hint": "δ_min = 90° gives sin(75°)/sin(30°) ≈ 0.966/0.5 = 1.932, which exceeds √3.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The dispersive power of a prism depends on:", "explanation": "Dispersive power ω = (n_v − n_r)/(n_y − 1), where n_v, n_r, and n_y are the refractive indices for violet, red, and yellow light respectively. It depends solely on the material of the prism (i.e., how much the refractive index varies with wavelength) and is independent of the angle of the prism.", "correct_answer": "D", "concept_tags": ["dispersive-power", "prism-material", "dispersion"], "payload": {"question_id": "cuet-phy-ray-prism-08", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "The angle of the prism only", "is_correct": false}, {"key": "B", "text": "The angle of incidence only", "is_correct": false}, {"key": "C", "text": "Both the angle of the prism and the material", "is_correct": false}, {"key": "D", "text": "The material of the prism only", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The angle of the prism affects the angular dispersion but not the dispersive power, which is a ratio independent of A.", "misconception": "Confusing angular dispersion with dispersive power"}, {"option_key": "B", "hint": "The angle of incidence affects the deviation but the dispersive power is a material property independent of the incident angle.", "misconception": null}, {"option_key": "C", "hint": "Although angular dispersion depends on A, the dispersive power ω = (n_v − n_r)/(n_y − 1) does not depend on the prism angle.", "misconception": "Confusing dispersive power with angular dispersion"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A thin prism of angle 6° produces a deviation of 3°. The refractive index of the prism material is:", "explanation": "For a thin prism, the deviation is given by δ = (n − 1)A. Substituting δ = 3° and A = 6°: 3 = (n − 1) × 6, so n − 1 = 0.5, giving n = 1.5.", "correct_answer": "B", "concept_tags": ["thin-prism", "deviation", "refractive-index"], "payload": {"question_id": "cuet-phy-ray-prism-09", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "1.33", "is_correct": false}, {"key": "B", "text": "1.5", "is_correct": true}, {"key": "C", "text": "2.0", "is_correct": false}, {"key": "D", "text": "1.6", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "n = 1.33 would give δ = (1.33 − 1) × 6 = 0.33 × 6 = 1.98°, not 3°.", "misconception": null}, {"option_key": "C", "hint": "n = 2.0 would give δ = (2.0 − 1) × 6 = 1 × 6 = 6°, not 3°.", "misconception": null}, {"option_key": "D", "hint": "n = 1.6 would give δ = (1.6 − 1) × 6 = 0.6 × 6 = 3.6°, which is close but not exactly 3°.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the formation of a rainbow, the light undergoes:", "explanation": "A rainbow is formed when sunlight enters a water droplet, undergoes refraction at the surface, total internal reflection inside the droplet, and then refraction again as it exits. The dispersion during refraction splits white light into its component colours.", "correct_answer": "C", "concept_tags": ["rainbow", "refraction", "total-internal-reflection", "dispersion"], "payload": {"question_id": "cuet-phy-ray-prism-10", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Only refraction", "is_correct": false}, {"key": "B", "text": "Only total internal reflection", "is_correct": false}, {"key": "C", "text": "Refraction, internal reflection and dispersion", "is_correct": true}, {"key": "D", "text": "Diffraction and interference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Refraction alone cannot explain the formation of a rainbow; internal reflection inside the water droplet is essential to redirect light back towards the observer.", "misconception": null}, {"option_key": "B", "hint": "Total internal reflection alone cannot produce the spectrum of colours; refraction-induced dispersion is needed to separate the colours.", "misconception": null}, {"option_key": "D", "hint": "While diffraction and interference can produce colours (as in thin films), rainbow formation is primarily due to refraction, internal reflection and dispersion in water droplets.", "misconception": "Confusing rainbow formation with thin-film interference"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A ray of light is incident on an equilateral glass prism (n = 1.5) placed on a horizontal surface. For the ray to undergo total internal reflection at the second face, the minimum angle of incidence at the first face must satisfy:", "explanation": "For TIR at the second face, the angle of refraction r₂ at that face must be at least equal to the critical angle C, where sin C = 1/n = 1/1.5 = 2/3. For an equilateral prism, A = 60° and r₁ + r₂ = A. For r₂ = C, r₁ = 60° − C. Using Snell''s law at the first face: sin i = n sin r₁ = 1.5 × sin(60° − C). Since sin C = 2/3, we get C ≈ 41.8°, so r₁ = 18.2°. Then sin i = 1.5 × sin 18.2° ≈ 1.5 × 0.312 ≈ 0.468, giving i ≈ 27.9° ≈ 28°.", "correct_answer": "A", "concept_tags": ["total-internal-reflection", "prism", "critical-angle", "snell-law"], "payload": {"question_id": "cuet-phy-ray-prism-11", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "The angle of incidence must be at least approximately 28°", "is_correct": true}, {"key": "B", "text": "The angle of incidence must be at least 60°", "is_correct": false}, {"key": "C", "text": "Total internal reflection is not possible in this prism", "is_correct": false}, {"key": "D", "text": "The angle of incidence must be at least 45°", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "60° is the prism angle itself. The minimum angle of incidence for TIR at the second face is obtained by setting r₂ = C and computing i from Snell''s law.", "misconception": null}, {"option_key": "C", "hint": "TIR is possible at the second face of this prism if the angle of incidence at the first face is large enough to make r₂ ≥ C.", "misconception": "Incorrectly assuming TIR cannot occur in a prism"}, {"option_key": "D", "hint": "45° would correspond to a different prism geometry or refractive index. The calculation with n = 1.5 and A = 60° gives approximately 28°.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two thin prisms of angles 5° and 3° are made of materials with refractive indices 1.5 and 1.7 respectively. They are combined to produce dispersion without deviation. The ratio of their angular dispersions for the prism combination that achieves this is:", "explanation": "For no net deviation: (n₁ − 1)A₁ = (n₂ − 1)A₂, i.e., 0.5 × 5 = 0.7 × 3, which gives 2.5 = 2.1. Since these aren''t exactly equal, one prism must be inverted and the condition requires adjustable angles. However, in the standard NEET approach, the angular dispersion ratio equals the ratio of (n_v − n_r)A for each prism. For deviation without dispersion (or vice versa), the angular dispersions are in the ratio of the deviations: δ₁/δ₂ = (n₁ − 1)A₁ / (n₂ − 1)A₂ = 2.5/2.1 = 25:21.", "correct_answer": "D", "concept_tags": ["combination-of-prisms", "dispersion-without-deviation", "angular-dispersion"], "payload": {"question_id": "cuet-phy-ray-prism-12", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "5 : 3", "is_correct": false}, {"key": "B", "text": "3 : 5", "is_correct": false}, {"key": "C", "text": "21 : 25", "is_correct": false}, {"key": "D", "text": "25 : 21", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "5:3 is just the ratio of prism angles and does not account for the different refractive indices of the materials.", "misconception": "Ignoring the role of refractive index in computing deviations"}, {"option_key": "B", "hint": "3:5 is the inverse of the prism angle ratio and has no physical basis for this problem.", "misconception": null}, {"option_key": "C", "hint": "21:25 is the inverse of the correct ratio. The first prism (larger δ) has the greater angular dispersion.", "misconception": "Inverting the ratio of angular dispersions"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Diamonds sparkle brilliantly due to total internal reflection.\nReason (R): Diamond has a very high refractive index (n ≈ 2.42) resulting in a small critical angle of about 24.4°.", "explanation": "Both the assertion and reason are correct, and the reason correctly explains the assertion. Diamond''s very high refractive index gives it a very small critical angle (sin C = 1/2.42, C ≈ 24.4°). This means light entering the diamond undergoes TIR at most internal surfaces, bouncing multiple times before emerging, which produces the brilliant sparkle.", "correct_answer": "A", "concept_tags": ["diamond", "total-internal-reflection", "critical-angle", "refractive-index"], "payload": {"question_id": "cuet-phy-ray-prism-13", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The small critical angle (from high n) is precisely why TIR occurs so readily inside diamond, directly explaining the sparkle.", "misconception": "Failing to connect high n and small critical angle to multiple TIR events"}, {"option_key": "C", "hint": "The reason is factually correct — diamond does have n ≈ 2.42 and a critical angle of about 24.4°.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; diamonds do sparkle due to multiple total internal reflections.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): At minimum deviation through a prism, the refracted ray inside the prism travels parallel to the base of the prism.\nReason (R): At minimum deviation, the angle of incidence at the first face equals the angle of emergence at the second face.", "explanation": "Both A and R are correct. At minimum deviation, i = e and r₁ = r₂ = A/2, which makes the ray inside the prism symmetric with respect to the prism. For a prism with its base horizontal, this symmetric path means the internal ray is parallel to the base. The reason (i = e) is the correct explanation because this symmetry condition leads to the parallel path inside.", "correct_answer": "A", "concept_tags": ["minimum-deviation", "prism-symmetry", "angle-of-incidence", "angle-of-emergence"], "payload": {"question_id": "cuet-phy-ray-prism-14", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The condition i = e directly leads to r₁ = r₂ = A/2, which makes the internal ray parallel to the base. So R is the correct explanation of A.", "misconception": null}, {"option_key": "C", "hint": "The reason is correct — at minimum deviation, it is well established that the angle of incidence equals the angle of emergence.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct — at minimum deviation, the refracted ray inside the prism does travel parallel to the base, which can be verified from the symmetry condition.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the optical phenomena in Column I with their correct descriptions in Column II:\n\nColumn I:\nA. Total internal reflection\nB. Dispersion\nC. Angular dispersion\nD. Dispersive power\n\nColumn II:\n1. Splitting of white light into component colours by a prism\n2. Ratio of angular dispersion to mean deviation\n3. Reflection of light when angle of incidence exceeds the critical angle in a denser medium\n4. Difference in deviations of violet and red light through a prism", "explanation": "Total internal reflection occurs when the angle of incidence in a denser medium exceeds the critical angle (A-3). Dispersion is the splitting of white light into its spectrum (B-1). Angular dispersion is the difference in deviations between violet and red light (C-4). Dispersive power is the ratio of angular dispersion to the mean deviation (D-2).", "correct_answer": "C", "concept_tags": ["total-internal-reflection", "dispersion", "angular-dispersion", "dispersive-power"], "payload": {"question_id": "cuet-phy-ray-prism-15", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "A-3, B-4, C-1, D-2", "is_correct": false}, {"key": "B", "text": "A-1, B-3, C-4, D-2", "is_correct": false}, {"key": "C", "text": "A-3, B-1, C-4, D-2", "is_correct": true}, {"key": "D", "text": "A-3, B-1, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Dispersion is the splitting of light (B-1), not the deviation difference, and angular dispersion is the deviation difference (C-4), not the splitting.", "misconception": "Confusing dispersion with angular dispersion"}, {"option_key": "B", "hint": "This incorrectly assigns TIR to splitting of light (A-1) and dispersion to the critical angle condition (B-3).", "misconception": null}, {"option_key": "D", "hint": "This swaps C and D. Angular dispersion is δ_v − δ_r (C-4), while dispersive power is the ratio (δ_v − δ_r)/δ_y (D-2).", "misconception": "Interchanging angular dispersion and dispersive power"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the applications in Column I with the underlying principle in Column II:\n\nColumn I:\nA. Optical fibre communication\nB. Sparkling of diamond\nC. Formation of secondary rainbow\nD. Mirage in deserts\n\nColumn II:\n1. Two total internal reflections inside a water droplet\n2. Gradual refraction and TIR in air layers of varying density\n3. Repeated TIR at core-cladding interface\n4. Multiple TIR due to small critical angle", "explanation": "Optical fibres use repeated TIR at the core-cladding interface (A-3). Diamond sparkles due to multiple TIR because of its very small critical angle (B-4). A secondary rainbow involves two total internal reflections inside each water droplet (C-1). Mirages are formed by gradual refraction in hot air layers of varying density followed by TIR (D-2).", "correct_answer": "B", "concept_tags": ["optical-fibre", "diamond", "rainbow", "mirage", "total-internal-reflection"], "payload": {"question_id": "cuet-phy-ray-prism-16", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-1, D-2", "is_correct": true}, {"key": "C", "text": "A-4, B-3, C-1, D-2", "is_correct": false}, {"key": "D", "text": "A-3, B-4, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Diamond sparkles due to its small critical angle (B-4), and the secondary rainbow involves two TIR events (C-1), not the reverse.", "misconception": null}, {"option_key": "C", "hint": "Optical fibres use repeated TIR at the core-cladding interface (A-3), not multiple TIR due to small critical angle (A-4).", "misconception": "Confusing optical fibre TIR mechanism with diamond''s TIR mechanism"}, {"option_key": "D", "hint": "This swaps C and D. The secondary rainbow involves two TIR events in a droplet (C-1), while mirages involve varying air density (D-2).", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The critical angle for a medium with refractive index 2 with respect to air is 30°.", "explanation": "The critical angle C is given by sin C = 1/n. For n = 2, sin C = 1/2 = 0.5, so C = sin⁻¹(0.5) = 30°. This statement is true.", "correct_answer": "A", "concept_tags": ["critical-angle", "refractive-index", "total-internal-reflection"], "payload": {"question_id": "cuet-phy-ray-prism-17", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The calculation sin C = 1/n = 1/2 gives C = 30°, confirming the statement is true.", "misconception": "Incorrectly computing the critical angle"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The deviation produced by a prism increases continuously as the angle of incidence increases from 0° to 90°.", "explanation": "This statement is false. As the angle of incidence increases from its minimum value, the deviation first decreases, reaches a minimum value (minimum deviation), and then increases again. The deviation-vs-incidence curve is U-shaped, not monotonically increasing.", "correct_answer": "B", "concept_tags": ["prism", "deviation", "angle-of-incidence", "minimum-deviation"], "payload": {"question_id": "cuet-phy-ray-prism-18", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The deviation first decreases to a minimum value and then increases. It does not increase continuously.", "misconception": "Assuming deviation increases monotonically with angle of incidence"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The angular dispersion produced by a thin prism of angle A for violet and red light is given by _____, where n_v and n_r are the refractive indices for violet and red light respectively.", "explanation": "For a thin prism, the deviation for any colour is δ = (n − 1)A. The angular dispersion is the difference in deviations of violet and red: δ_v − δ_r = (n_v − 1)A − (n_r − 1)A = (n_v − n_r)A. This formula shows angular dispersion depends on both the material (n_v − n_r) and the prism angle A.", "correct_answer": "C", "concept_tags": ["angular-dispersion", "thin-prism", "violet-red-deviation"], "payload": {"question_id": "cuet-phy-ray-prism-19", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "(n_v + n_r)A", "is_correct": false}, {"key": "B", "text": "(n_v − n_r)/A", "is_correct": false}, {"key": "C", "text": "(n_v − n_r)A", "is_correct": true}, {"key": "D", "text": "(n_v × n_r)A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Adding refractive indices (n_v + n_r) has no physical meaning in the context of angular dispersion, which is the difference in deviations.", "misconception": null}, {"option_key": "B", "hint": "Angular dispersion is proportional to A, not inversely proportional. Dividing by A gives the dispersive power (after normalisation), not angular dispersion.", "misconception": "Confusing angular dispersion formula with dispersive power"}, {"option_key": "D", "hint": "The product n_v × n_r has no relevance to angular dispersion. The correct expression involves the difference (n_v − n_r).", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A scuba diver is at the bottom of a swimming pool of depth 4 m. The refractive index of water is 4/3. The diver shines a torch upward. The light that exits the water surface forms a bright circle on the surface.\n\nWhat is the radius of this bright circle?", "explanation": "Light exits the water surface only if the angle of incidence is less than the critical angle C. The critical angle is given by sin C = 1/n = 3/4. The radius r of the bright circle is related to the depth h by r = h × tan C. Since sin C = 3/4, cos C = √(1 − 9/16) = √(7/16) = √7/4. So tan C = sin C/cos C = (3/4)/(√7/4) = 3/√7. Therefore r = 4 × 3/√7 = 12/√7 ≈ 4.53 m ≈ 4.5 m.", "correct_answer": "B", "concept_tags": ["critical-angle", "total-internal-reflection", "snell-law", "bright-circle"], "payload": {"question_id": "cuet-phy-ray-prism-20", "subtopic": "Prism and Dispersion", "topic_name": "Prism and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "3 m", "is_correct": false}, {"key": "B", "text": "12/√7 m", "is_correct": true}, {"key": "C", "text": "4 m", "is_correct": false}, {"key": "D", "text": "16/3 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 m would result from r = h × sin C = 4 × 3/4 = 3, but the correct formula uses tan C, not sin C.", "misconception": "Using sin C instead of tan C to find the radius"}, {"option_key": "C", "hint": "r = 4 m would imply tan C = 1 or C = 45°, but the critical angle for water (n = 4/3) is not 45°.", "misconception": null}, {"option_key": "D", "hint": "16/3 results from an incorrect formula. The correct approach gives r = h × tan C = 12/√7 m.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A ray of light is incident on a plane mirror at an angle of 30° with the mirror surface. What is the angle of reflection?", "explanation": "The angle of incidence is measured from the normal, not the surface. If the ray makes 30° with the mirror surface, the angle of incidence is 90° − 30° = 60°. By the law of reflection, the angle of reflection equals the angle of incidence, so it is 60°.", "correct_answer": "C", "concept_tags": ["law-of-reflection", "angle-of-incidence", "plane-mirror"], "payload": {"question_id": "cuet-phy-ray-reflection-01", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "60°", "is_correct": true}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30° is the angle the ray makes with the mirror surface, not with the normal. The angle of reflection is measured from the normal.", "misconception": "Confusing angle with surface and angle with normal"}, {"option_key": "B", "hint": "45° would be correct only if the ray made 45° with the surface, which is not the case here.", "misconception": null}, {"option_key": "D", "hint": "90° would mean the reflected ray is along the normal, which only happens for normal incidence.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The image formed by a plane mirror is:", "explanation": "A plane mirror always forms a virtual, erect image that is laterally inverted and of the same size as the object. The image is located as far behind the mirror as the object is in front of it.", "correct_answer": "B", "concept_tags": ["plane-mirror", "virtual-image", "image-characteristics"], "payload": {"question_id": "cuet-phy-ray-reflection-02", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "Real, erect and of same size", "is_correct": false}, {"key": "B", "text": "Virtual, erect and of same size", "is_correct": true}, {"key": "C", "text": "Virtual, inverted and magnified", "is_correct": false}, {"key": "D", "text": "Real, inverted and of same size", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A plane mirror cannot form a real image because the reflected rays diverge and only appear to meet behind the mirror.", "misconception": "Confusing virtual and real images in plane mirrors"}, {"option_key": "C", "hint": "The image in a plane mirror is erect (not inverted top-to-bottom) and of the same size, not magnified.", "misconception": "Confusing lateral inversion with top-bottom inversion"}, {"option_key": "D", "hint": "Plane mirrors do not form real images; they always produce virtual images that cannot be captured on a screen.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The focal length of a concave mirror is 15 cm. What is its radius of curvature?", "explanation": "For a spherical mirror, the radius of curvature R is related to the focal length f by the relation R = 2f. Therefore, R = 2 × 15 = 30 cm.", "correct_answer": "A", "concept_tags": ["concave-mirror", "focal-length", "radius-of-curvature"], "payload": {"question_id": "cuet-phy-ray-reflection-03", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "30 cm", "is_correct": true}, {"key": "B", "text": "15 cm", "is_correct": false}, {"key": "C", "text": "7.5 cm", "is_correct": false}, {"key": "D", "text": "45 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "15 cm is the focal length itself, not the radius of curvature. R = 2f, not R = f.", "misconception": "Confusing focal length with radius of curvature"}, {"option_key": "C", "hint": "7.5 cm would result from dividing f by 2 instead of multiplying. The correct relation is R = 2f.", "misconception": "Inverting the R-f relationship"}, {"option_key": "D", "hint": "45 cm would result from R = 3f, which is not the correct relationship for spherical mirrors.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When light travels from a denser medium to a rarer medium, it bends:", "explanation": "According to Snell''s law (n₁ sin θ₁ = n₂ sin θ₂), when light goes from a denser to a rarer medium (n₁ > n₂), the angle of refraction θ₂ is greater than the angle of incidence θ₁. Thus the refracted ray bends away from the normal.", "correct_answer": "D", "concept_tags": ["refraction", "snell-law", "denser-rarer-medium"], "payload": {"question_id": "cuet-phy-ray-reflection-04", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "Towards the normal", "is_correct": false}, {"key": "B", "text": "Along the normal", "is_correct": false}, {"key": "C", "text": "Parallel to the surface", "is_correct": false}, {"key": "D", "text": "Away from the normal", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Light bends towards the normal when going from a rarer to a denser medium, not the other way around.", "misconception": "Reversing the direction of bending in refraction"}, {"option_key": "B", "hint": "Light travels along the normal only when the angle of incidence is 0° (normal incidence), regardless of media.", "misconception": null}, {"option_key": "C", "hint": "Light becomes parallel to the surface only at the critical angle during total internal reflection, not in general refraction.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b13');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An object is placed at 20 cm in front of a concave mirror of focal length 10 cm. The magnification produced is:", "explanation": "Using the mirror formula 1/v + 1/u = 1/f with u = −20 cm and f = −10 cm: 1/v = 1/(−10) − 1/(−20) = −1/10 + 1/20 = −1/20, so v = −20 cm. Magnification m = −v/u = −(−20)/(−20) = −1. The image is real, inverted and of same size.", "correct_answer": "B", "concept_tags": ["concave-mirror", "mirror-formula", "magnification"], "payload": {"question_id": "cuet-phy-ray-reflection-05", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "+1", "is_correct": false}, {"key": "B", "text": "−1", "is_correct": true}, {"key": "C", "text": "−2", "is_correct": false}, {"key": "D", "text": "+2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+1 magnification means a virtual, erect image of same size, which occurs for a plane mirror, not for an object at 2f of a concave mirror.", "misconception": "Ignoring the sign convention for magnification in mirrors"}, {"option_key": "C", "hint": "Magnification of −2 would occur when the object is placed between f and 2f (e.g., at 15 cm for f = 10 cm), not at 2f.", "misconception": null}, {"option_key": "D", "hint": "+2 would imply a virtual, erect, magnified image, which occurs when the object is between the pole and focus.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A convex mirror is used as a rear-view mirror in vehicles primarily because it:", "explanation": "A convex mirror always forms a virtual, erect and diminished image for all positions of the object. This gives a wider field of view compared to a plane mirror, making it ideal for rear-view mirrors in vehicles where observing a large area behind is essential for safety.", "correct_answer": "C", "concept_tags": ["convex-mirror", "field-of-view", "rear-view-mirror", "applications"], "payload": {"question_id": "cuet-phy-ray-reflection-06", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "understand", "options": [{"key": "A", "text": "Forms a real and magnified image", "is_correct": false}, {"key": "B", "text": "Forms a virtual and magnified image", "is_correct": false}, {"key": "C", "text": "Forms an erect, diminished image and provides a wider field of view", "is_correct": true}, {"key": "D", "text": "Forms an image of the same size as the object", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Convex mirrors never form real images; they always form virtual images since reflected rays diverge.", "misconception": "Confusing convex mirror properties with concave mirror properties"}, {"option_key": "B", "hint": "Convex mirrors always form diminished images, not magnified ones. Only concave mirrors can produce magnified images.", "misconception": null}, {"option_key": "D", "hint": "A convex mirror always produces a diminished image (smaller than the object), never the same size.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The refractive index of glass with respect to air is 1.5. What is the speed of light in glass if the speed of light in vacuum is 3 × 10⁸ m/s?", "explanation": "The refractive index n of a medium is defined as n = c/v, where c is the speed of light in vacuum and v is the speed in the medium. Therefore, v = c/n = (3 × 10⁸)/1.5 = 2 × 10⁸ m/s.", "correct_answer": "A", "concept_tags": ["refractive-index", "speed-of-light", "optical-density"], "payload": {"question_id": "cuet-phy-ray-reflection-07", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁸ m/s", "is_correct": true}, {"key": "B", "text": "4.5 × 10⁸ m/s", "is_correct": false}, {"key": "C", "text": "1.5 × 10⁸ m/s", "is_correct": false}, {"key": "D", "text": "3 × 10⁸ m/s", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "4.5 × 10⁸ m/s = c × n, which is greater than c. No material medium can allow light to travel faster than c.", "misconception": "Multiplying c by n instead of dividing"}, {"option_key": "C", "hint": "1.5 × 10⁸ m/s would correspond to n = 2, not 1.5. Check the calculation v = c/n.", "misconception": null}, {"option_key": "D", "hint": "3 × 10⁸ m/s is the speed in vacuum. Light slows down in any material medium with n > 1.", "misconception": "Assuming speed of light is the same in all media"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An object is placed at 30 cm from a convex mirror of focal length 20 cm. The position of the image from the mirror is:", "explanation": "For a convex mirror, f = +20 cm and u = −30 cm. Using mirror formula: 1/v = 1/f − 1/u = 1/20 − 1/(−30) = 1/20 + 1/30 = (3 + 2)/60 = 5/60 = 1/12. So v = +12 cm. The positive sign confirms the image is behind the mirror (virtual).", "correct_answer": "D", "concept_tags": ["convex-mirror", "mirror-formula", "image-distance"], "payload": {"question_id": "cuet-phy-ray-reflection-08", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "60 cm behind the mirror", "is_correct": false}, {"key": "B", "text": "20 cm in front of the mirror", "is_correct": false}, {"key": "C", "text": "15 cm behind the mirror", "is_correct": false}, {"key": "D", "text": "12 cm behind the mirror", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "60 cm is far too large; for a convex mirror the image always lies between the pole and the focus, i.e., within 20 cm behind the mirror.", "misconception": null}, {"option_key": "B", "hint": "A convex mirror always forms a virtual image behind the mirror, never a real image in front.", "misconception": "Confusing convex mirror with concave mirror image positions"}, {"option_key": "C", "hint": "15 cm results from an arithmetic error. Carefully compute 1/20 + 1/30 = 5/60 = 1/12, giving v = 12 cm.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A ray of light passes from glass (n = 1.5) into water (n = 1.33). If the angle of incidence is 30°, the angle of refraction is approximately:", "explanation": "Applying Snell''s law: n₁ sin θ₁ = n₂ sin θ₂, so 1.5 × sin 30° = 1.33 × sin θ₂. This gives sin θ₂ = (1.5 × 0.5)/1.33 = 0.75/1.33 = 0.564. Therefore θ₂ = sin⁻¹(0.564) ≈ 34.3° ≈ 34°.", "correct_answer": "B", "concept_tags": ["snell-law", "refraction", "refractive-index"], "payload": {"question_id": "cuet-phy-ray-reflection-09", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "26°", "is_correct": false}, {"key": "B", "text": "34°", "is_correct": true}, {"key": "C", "text": "45°", "is_correct": false}, {"key": "D", "text": "30°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "26° would correspond to bending towards the normal, but light going from a denser (glass) to a less dense medium (water) bends away from the normal.", "misconception": "Reversing the direction of bending at the interface"}, {"option_key": "C", "hint": "45° is too large; sin 45° = 0.707, but the calculation gives sin θ₂ ≈ 0.564.", "misconception": null}, {"option_key": "D", "hint": "The refracted angle equals the incident angle only if both media have the same refractive index, which is not the case here.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A biconvex lens has radii of curvature R₁ = 20 cm and R₂ = 30 cm and refractive index 1.5. Its focal length using the lens maker''s equation is:", "explanation": "Using the lens maker''s equation: 1/f = (n − 1)[1/R₁ − 1/R₂] = (1.5 − 1)[1/20 − 1/(−30)] = 0.5 × [1/20 + 1/30] = 0.5 × (3 + 2)/60 = 0.5 × 5/60 = 0.5/12 = 1/24. Therefore f = 24 cm.", "correct_answer": "C", "concept_tags": ["lens-maker-equation", "biconvex-lens", "focal-length"], "payload": {"question_id": "cuet-phy-ray-reflection-10", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "12 cm", "is_correct": false}, {"key": "B", "text": "20 cm", "is_correct": false}, {"key": "C", "text": "24 cm", "is_correct": true}, {"key": "D", "text": "30 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "12 cm results from forgetting the (n − 1) factor and using 1/f = 1/R₁ + 1/R₂ directly.", "misconception": "Omitting the (n − 1) factor in the lens maker''s equation"}, {"option_key": "B", "hint": "20 cm is just the value of R₁; the focal length depends on both radii and the refractive index.", "misconception": null}, {"option_key": "D", "hint": "30 cm is just the value of R₂; the correct calculation involves both radii in the lens maker''s formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A concave mirror forms a real image of an object placed beyond its centre of curvature. If the object is moved towards the focus of the mirror, the image:", "explanation": "When the object is beyond C, the real image lies between F and C. As the object moves from beyond C towards F, the image moves from between F and C towards infinity. Thus the image moves farther from the mirror and its size increases (magnification increases in magnitude).", "correct_answer": "D", "concept_tags": ["concave-mirror", "image-movement", "magnification", "object-at-focus"], "payload": {"question_id": "cuet-phy-ray-reflection-11", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Moves towards the mirror and becomes smaller", "is_correct": false}, {"key": "B", "text": "Remains at the same position with the same size", "is_correct": false}, {"key": "C", "text": "Moves towards the mirror and becomes larger", "is_correct": false}, {"key": "D", "text": "Moves away from the mirror and becomes larger", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This is the reverse of what happens. As the object approaches the focus, the image recedes and enlarges, not the opposite.", "misconception": "Reversing the direction of image motion for concave mirrors"}, {"option_key": "B", "hint": "The image position and size remain unchanged only if the object position does not change. Moving the object changes the image.", "misconception": null}, {"option_key": "C", "hint": "The image does become larger, but it moves away from the mirror, not towards it, as the object approaches the focus.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A thin convex lens of focal length 20 cm is placed in contact with a thin concave lens of focal length 30 cm. The combination acts as a:", "explanation": "For lenses in contact, the equivalent focal length is given by 1/f = 1/f₁ + 1/f₂ = 1/20 + 1/(−30) = 3/60 − 2/60 = 1/60. So f = +60 cm. Since the focal length is positive, the combination acts as a converging (convex) lens of focal length 60 cm.", "correct_answer": "A", "concept_tags": ["combination-of-lenses", "equivalent-focal-length", "convex-lens", "concave-lens"], "payload": {"question_id": "cuet-phy-ray-reflection-12", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "analyze", "options": [{"key": "A", "text": "Converging lens of focal length 60 cm", "is_correct": true}, {"key": "B", "text": "Diverging lens of focal length 60 cm", "is_correct": false}, {"key": "C", "text": "Converging lens of focal length 10 cm", "is_correct": false}, {"key": "D", "text": "Diverging lens of focal length 10 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The calculated focal length is +60 cm (positive), which indicates a converging lens, not a diverging one.", "misconception": "Confusing the sign of the equivalent focal length"}, {"option_key": "C", "hint": "10 cm results from incorrectly subtracting: 1/20 − 1/30 ≠ 1/10. The correct calculation gives 1/60.", "misconception": "Arithmetic error in combining lens powers"}, {"option_key": "D", "hint": "Neither the focal length (60 cm, not 10 cm) nor the nature (converging, not diverging) matches this option.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A concave mirror can form both real and virtual images.\nReason (R): When an object is placed between the pole and the focus of a concave mirror, the reflected rays diverge and appear to come from behind the mirror.", "explanation": "Both the assertion and reason are correct. A concave mirror forms real images when the object is beyond the focus and virtual images when the object is between the pole and focus. The reason correctly explains why a virtual image forms in the latter case — the reflected rays diverge and appear to originate from behind the mirror.", "correct_answer": "A", "concept_tags": ["concave-mirror", "real-virtual-image", "image-formation"], "payload": {"question_id": "cuet-phy-ray-reflection-13", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains how the virtual image forms, which is one part of the assertion. Hence R is the correct explanation of A.", "misconception": "Failing to see the causal link between R and A"}, {"option_key": "C", "hint": "The reason is physically accurate — reflected rays from an object between P and F do diverge, forming a virtual image behind the mirror.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; concave mirrors can indeed form both real and virtual images depending on object position.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The refractive index of a medium depends on the wavelength of light used.\nReason (R): The speed of light in a medium is the same for all wavelengths.", "explanation": "The assertion is correct because the refractive index n = c/v, and the speed v of light in a dispersive medium varies with wavelength (this is the cause of dispersion). The reason is incorrect because the speed of light in a material medium does depend on wavelength — violet light travels slower than red light in glass, for example.", "correct_answer": "C", "concept_tags": ["refractive-index", "dispersion", "wavelength-dependence", "speed-of-light"], "payload": {"question_id": "cuet-phy-ray-reflection-14", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The reason is factually incorrect — the speed of light in a material medium does vary with wavelength, causing dispersion.", "misconception": null}, {"option_key": "B", "hint": "Since the reason is incorrect (speed does depend on wavelength in a medium), this option cannot be chosen.", "misconception": "Believing speed of light is wavelength-independent in all media"}, {"option_key": "D", "hint": "The assertion is correct; refractive index is wavelength-dependent (e.g., Cauchy''s equation describes this dependence).", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following mirror types with the nature of the image formed:\n\nColumn I:\nA. Concave mirror (object at infinity)\nB. Convex mirror (any object position)\nC. Concave mirror (object between P and F)\nD. Plane mirror\n\nColumn II:\n1. Virtual, erect, same size\n2. Real, inverted, highly diminished (at focus)\n3. Virtual, erect, diminished\n4. Virtual, erect, magnified", "explanation": "A concave mirror forms a real, inverted, point-sized image at the focus when the object is at infinity (A-2). A convex mirror always forms a virtual, erect, diminished image (B-3). A concave mirror with the object between P and F gives a virtual, erect, magnified image (C-4). A plane mirror forms a virtual, erect, same-sized image (D-1).", "correct_answer": "B", "concept_tags": ["mirror-types", "image-characteristics", "concave-mirror", "convex-mirror", "plane-mirror"], "payload": {"question_id": "cuet-phy-ray-reflection-15", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "C", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly assigns a virtual magnified image to a convex mirror (B-4). Convex mirrors always form diminished images.", "misconception": "Confusing image properties of convex and concave mirrors"}, {"option_key": "C", "hint": "A-4 is wrong; a concave mirror with the object at infinity forms a real diminished image at the focus, not a virtual magnified one.", "misconception": null}, {"option_key": "D", "hint": "This option assigns completely incorrect image types to all mirrors and has no physical basis.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the optical phenomena in Column I with their correct physical basis in Column II:\n\nColumn I:\nA. Twinkling of stars\nB. Apparent depth of a swimming pool is less than actual depth\nC. Lateral displacement of a ray through a glass slab\nD. Bending of light around sharp edges\n\nColumn II:\n1. Refraction at parallel surfaces\n2. Atmospheric refraction due to varying refractive index\n3. Refraction at a plane surface\n4. Diffraction", "explanation": "Twinkling of stars is caused by atmospheric refraction due to turbulent layers with varying refractive index (A-2). The apparent decrease in depth of a pool is due to refraction at the plane water surface (B-3). Lateral displacement through a glass slab occurs because of refraction at two parallel surfaces (C-1). Bending of light around sharp edges is diffraction (D-4).", "correct_answer": "D", "concept_tags": ["atmospheric-refraction", "apparent-depth", "lateral-displacement", "diffraction"], "payload": {"question_id": "cuet-phy-ray-reflection-16", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-2, C-1, D-4", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-4, D-1", "is_correct": false}, {"key": "D", "text": "A-2, B-3, C-1, D-4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Apparent depth is due to refraction at a single plane surface (B-3), while lateral displacement involves two parallel surfaces (C-1).", "misconception": null}, {"option_key": "B", "hint": "Twinkling of stars (A) is due to atmospheric refraction (2), not refraction at a single plane surface (3).", "misconception": "Confusing atmospheric refraction with simple refraction"}, {"option_key": "C", "hint": "This incorrectly assigns diffraction (4) to lateral displacement and refraction at parallel surfaces (1) to bending around edges.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The angle of incidence is equal to the angle of reflection for all reflecting surfaces.", "explanation": "This is a statement of the law of reflection, which holds true for all reflecting surfaces — whether plane, concave, convex, or irregular. The angles are measured with respect to the normal at the point of incidence.", "correct_answer": "A", "concept_tags": ["law-of-reflection", "angle-of-incidence", "angle-of-reflection"], "payload": {"question_id": "cuet-phy-ray-reflection-17", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The law of reflection (angle of incidence = angle of reflection) is universally valid for all reflecting surfaces.", "misconception": "Thinking the law of reflection applies only to plane mirrors"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A convex mirror can form a real image of a real object.", "explanation": "This statement is false. A convex mirror always forms a virtual, erect and diminished image for any position of a real object. The reflected rays always diverge and only appear to meet behind the mirror, so the image is always virtual.", "correct_answer": "B", "concept_tags": ["convex-mirror", "virtual-image", "image-formation"], "payload": {"question_id": "cuet-phy-ray-reflection-18", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A convex mirror cannot form a real image of a real object. The diverging nature of the mirror ensures all images are virtual.", "misconception": "Confusing convex mirror with concave mirror capabilities"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The power of a convex lens of focal length 25 cm is _____ dioptre.", "explanation": "The power of a lens is given by P = 1/f, where f is in metres. Converting 25 cm to metres: f = 0.25 m. Therefore P = 1/0.25 = +4 D. The positive sign indicates a converging lens.", "correct_answer": "D", "concept_tags": ["power-of-lens", "focal-length", "dioptre"], "payload": {"question_id": "cuet-phy-ray-reflection-19", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "+0.25", "is_correct": false}, {"key": "B", "text": "+25", "is_correct": false}, {"key": "C", "text": "−4", "is_correct": false}, {"key": "D", "text": "+4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "+0.25 would be the focal length in metres, not the power. Power = 1/f, not f itself.", "misconception": "Confusing focal length (in metres) with power"}, {"option_key": "B", "hint": "+25 results from using f in cm directly in P = 1/f. The focal length must be converted to metres first.", "misconception": "Forgetting to convert cm to m when calculating power"}, {"option_key": "C", "hint": "−4 D would be the power of a concave (diverging) lens. A convex lens has positive power.", "misconception": "Using wrong sign for convex lens power"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student places a 5 cm tall candle at a distance of 25 cm from a concave mirror of focal length 15 cm. She observes a clear image on a screen placed on the same side as the candle.\n\nWhat is the height of the image formed on the screen?", "explanation": "Using mirror formula with u = −25 cm and f = −15 cm: 1/v = 1/f − 1/u = 1/(−15) − 1/(−25) = −1/15 + 1/25 = (−5 + 3)/75 = −2/75. So v = −37.5 cm. Magnification m = −v/u = −(−37.5)/(−25) = −1.5. Image height = m × object height = −1.5 × 5 = −7.5 cm. The negative sign indicates the image is inverted. The magnitude of the image height is 7.5 cm.", "correct_answer": "C", "concept_tags": ["concave-mirror", "mirror-formula", "magnification", "image-height"], "payload": {"question_id": "cuet-phy-ray-reflection-20", "subtopic": "Reflection and Mirrors", "topic_name": "Reflection and Mirrors", "bloom_level": "apply", "options": [{"key": "A", "text": "5 cm, erect", "is_correct": false}, {"key": "B", "text": "3.33 cm, inverted", "is_correct": false}, {"key": "C", "text": "7.5 cm, inverted", "is_correct": true}, {"key": "D", "text": "10 cm, inverted", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "An image of the same height (5 cm) would occur only when the object is at the centre of curvature (2f = 30 cm), not at 25 cm.", "misconception": "Assuming the image size equals object size for all positions"}, {"option_key": "B", "hint": "3.33 cm results from an error in computing v. Carefully re-evaluate 1/(−15) − 1/(−25) to get v = −37.5 cm.", "misconception": null}, {"option_key": "D", "hint": "10 cm would require a magnification of 2, which does not match the object distance of 25 cm and focal length of 15 cm.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In single slit diffraction, the condition for the first minimum is:", "explanation": "In single slit Fraunhofer diffraction, destructive interference (minima) occurs when the path difference between the extreme rays from the slit equals an integral multiple of the wavelength. The condition for the nth minimum is a sin θ = nλ. For the first minimum, n = 1, so a sin θ = λ.", "correct_answer": "A", "concept_tags": ["single-slit-diffraction", "minima-condition", "path-difference"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-01", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "a sin θ = λ", "is_correct": true}, {"key": "B", "text": "a sin θ = λ/2", "is_correct": false}, {"key": "C", "text": "a sin θ = 2λ", "is_correct": false}, {"key": "D", "text": "a sin θ = 3λ/2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "a sin θ = λ/2 does not correspond to either a maximum or minimum in single slit diffraction. The minima occur at whole multiples of λ.", "misconception": "Confusing single slit diffraction minima with double slit interference conditions"}, {"option_key": "C", "hint": "a sin θ = 2λ gives the second minimum (n = 2), not the first.", "misconception": "Using wrong order number for the first minimum"}, {"option_key": "D", "hint": "a sin θ = 3λ/2 approximately corresponds to a secondary maximum, not the first minimum.", "misconception": "Confusing the condition for secondary maxima with minima"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The angular width of the central maximum in a single slit Fraunhofer diffraction pattern is:", "explanation": "In single slit Fraunhofer diffraction, the first minimum on either side occurs at sin θ = λ/a. For small angles, θ ≈ λ/a. Since the central maximum extends from the first minimum on one side to the first minimum on the other side, the total angular width of the central maximum is 2θ = 2λ/a.", "correct_answer": "B", "concept_tags": ["central-maximum", "angular-width", "single-slit-diffraction"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-02", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "λ/a", "is_correct": false}, {"key": "B", "text": "2λ/a", "is_correct": true}, {"key": "C", "text": "λ/2a", "is_correct": false}, {"key": "D", "text": "3λ/a", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "λ/a gives the angular half-width (from the centre to the first minimum on one side), not the full angular width.", "misconception": "Confusing half angular width with full angular width of central maximum"}, {"option_key": "C", "hint": "λ/2a is half the angular half-width and has no standard significance in the diffraction pattern.", "misconception": "Incorrectly halving the angular width formula"}, {"option_key": "D", "hint": "3λ/a does not correspond to the angular width of the central maximum. The central maximum spans only 2λ/a.", "misconception": "Using the wrong multiple of λ/a"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Rayleigh''s criterion, two point sources are just resolved when the central maximum of one falls on the:", "explanation": "Rayleigh''s criterion for the limit of resolution states that two point sources are just resolved when the central maximum of the diffraction pattern of one source falls on the first minimum of the diffraction pattern of the other. This provides a practical definition of the minimum angular separation for resolution.", "correct_answer": "C", "concept_tags": ["rayleigh-criterion", "resolving-power", "limit-of-resolution"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-03", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "Central maximum of the other", "is_correct": false}, {"key": "B", "text": "Second minimum of the other", "is_correct": false}, {"key": "C", "text": "First minimum of the other", "is_correct": true}, {"key": "D", "text": "First secondary maximum of the other", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If the central maxima of both patterns coincide, the two sources would appear as one and would be completely unresolved.", "misconception": "Thinking coincident maxima means just resolved"}, {"option_key": "B", "hint": "If the central maximum falls on the second minimum, the sources are well resolved (over-resolved), not just resolved.", "misconception": "Confusing well-resolved with just-resolved condition"}, {"option_key": "D", "hint": "The first secondary maximum is farther than the first minimum. This would give an over-resolved condition, not just resolved.", "misconception": "Confusing the positions of secondary maxima and minima"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Fraunhofer diffraction, the source of light and the screen are effectively at:", "explanation": "In Fraunhofer diffraction, both the source and the screen are effectively at infinite distance from the diffracting aperture. This is achieved in practice by using a collimating lens to produce parallel light from the source and a converging lens to focus the diffracted light onto the screen. In contrast, in Fresnel diffraction, either the source or the screen (or both) are at finite distances.", "correct_answer": "D", "concept_tags": ["fraunhofer-diffraction", "fresnel-diffraction", "parallel-rays"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-04", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "Finite distance from the slit", "is_correct": false}, {"key": "B", "text": "The focus of the lens", "is_correct": false}, {"key": "C", "text": "Very close to the slit", "is_correct": false}, {"key": "D", "text": "Infinite distance from the slit", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Finite distance from the slit describes Fresnel diffraction, not Fraunhofer diffraction.", "misconception": "Confusing Fresnel diffraction conditions with Fraunhofer diffraction"}, {"option_key": "B", "hint": "While lenses are used in the experimental setup, the condition is about the effective distance of the source and screen, which must be infinite.", "misconception": "Confusing the experimental setup with the defining condition"}, {"option_key": "C", "hint": "Placing the source very close to the slit would produce near-field (Fresnel) diffraction, not Fraunhofer diffraction.", "misconception": "Confusing near-field with far-field diffraction"}]}}]'::jsonb, 'deploy-2026-03-05-b13');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A single slit of width 0.1 mm is illuminated by a parallel beam of light of wavelength 6000 Å. The angular width of the central maximum on a screen is:", "explanation": "The angular width of the central maximum in single slit diffraction is 2θ = 2λ/a (for small angles). Given: a = 0.1 mm = 0.1 × 10⁻³ m = 10⁻⁴ m and λ = 6000 Å = 6 × 10⁻⁷ m. Angular width = 2λ/a = 2 × 6 × 10⁻⁷ / 10⁻⁴ = 12 × 10⁻³ rad = 1.2 × 10⁻² rad.", "correct_answer": "C", "concept_tags": ["angular-width", "central-maximum", "numerical-problem"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-05", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "6 × 10⁻³ rad", "is_correct": false}, {"key": "B", "text": "1.2 × 10⁻³ rad", "is_correct": false}, {"key": "C", "text": "1.2 × 10⁻² rad", "is_correct": true}, {"key": "D", "text": "6 × 10⁻² rad", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 × 10⁻³ rad is the half angular width (λ/a), not the full angular width of the central maximum.", "misconception": "Forgetting to multiply by 2 for the full angular width"}, {"option_key": "B", "hint": "This is off by a factor of 10. Check your unit conversion of slit width carefully.", "misconception": "Error in converting mm to metres"}, {"option_key": "D", "hint": "This value is too large. Recheck the calculation: 2 × 6 × 10⁻⁷ / 10⁻⁴ = 1.2 × 10⁻², not 6 × 10⁻².", "misconception": "Arithmetic error in the calculation"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the width of the slit in a single slit diffraction experiment is doubled, the width of the central maximum:", "explanation": "The angular width of the central maximum is 2λ/a. If the slit width ''a'' is doubled, the angular width becomes 2λ/(2a) = λ/a, which is half the original angular width. Since the linear width on the screen is proportional to the angular width (linear width = 2λD/a, where D is the distance to the screen), the width of the central maximum is halved when the slit width is doubled.", "correct_answer": "B", "concept_tags": ["slit-width-effect", "central-maximum", "diffraction-pattern"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-06", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Becomes doubled", "is_correct": false}, {"key": "B", "text": "Becomes halved", "is_correct": true}, {"key": "C", "text": "Remains unchanged", "is_correct": false}, {"key": "D", "text": "Becomes one-fourth", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The width of the central maximum is inversely proportional to the slit width. Doubling the slit width decreases, not increases, the central maximum width.", "misconception": "Thinking slit width and central maximum width are directly proportional"}, {"option_key": "C", "hint": "The angular width 2λ/a clearly depends on ''a''. Changing the slit width must change the pattern.", "misconception": "Ignoring the dependence of diffraction pattern on slit width"}, {"option_key": "D", "hint": "The width is inversely proportional to ''a'' (not to a²), so doubling ''a'' halves the width, not quarters it.", "misconception": "Confusing inverse proportionality with inverse square relationship"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The resolving power of a telescope can be increased by:", "explanation": "The minimum angular separation that a telescope can resolve is given by θ = 1.22λ/D, where D is the diameter of the objective lens (or mirror). Resolving power is the reciprocal of this: RP = D/(1.22λ). Therefore, increasing the diameter of the objective lens increases the resolving power. Using light of shorter wavelength also increases resolving power.", "correct_answer": "A", "concept_tags": ["resolving-power-telescope", "objective-diameter", "rayleigh-criterion"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-07", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Increasing the diameter of the objective lens", "is_correct": true}, {"key": "B", "text": "Increasing the focal length of the objective lens", "is_correct": false}, {"key": "C", "text": "Increasing the focal length of the eyepiece", "is_correct": false}, {"key": "D", "text": "Increasing the wavelength of light used", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The resolving power formula θ = 1.22λ/D depends on the diameter, not the focal length. Focal length affects magnifying power, not resolving power.", "misconception": "Confusing resolving power with magnifying power of a telescope"}, {"option_key": "C", "hint": "The eyepiece focal length affects magnification, not the ability to resolve two closely spaced objects.", "misconception": "Mixing up the roles of eyepiece and objective in resolution"}, {"option_key": "D", "hint": "Since θ = 1.22λ/D, increasing λ increases the minimum resolvable angle, which means the resolving power decreases.", "misconception": "Thinking larger wavelength gives better resolution"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a single slit diffraction pattern, the intensity of the central maximum is I₀. The intensity at the first secondary maximum is approximately:", "explanation": "In single slit diffraction, the intensity distribution is I = I₀ [sin(β/2)/(β/2)]², where β = (2πa sinθ)/λ. The first secondary maximum occurs approximately at β/2 ≈ 3π/2. The intensity at this point is I = I₀ [sin(3π/2)/(3π/2)]² = I₀ [1/(3π/2)]² = I₀ × 4/(9π²) ≈ I₀/22. This is approximately 4.5% of the central maximum intensity.", "correct_answer": "D", "concept_tags": ["intensity-distribution", "secondary-maxima", "single-slit-diffraction"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-08", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/2", "is_correct": false}, {"key": "B", "text": "I₀/4", "is_correct": false}, {"key": "C", "text": "I₀/9", "is_correct": false}, {"key": "D", "text": "I₀/22 (approximately)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "I₀/2 would mean the secondary maxima are very bright. In reality, the secondary maxima are much fainter than the central maximum.", "misconception": "Underestimating how rapidly intensity falls off in diffraction"}, {"option_key": "B", "hint": "I₀/4 is still too high. The intensity at secondary maxima follows the [sin(x)/x]² function which drops off steeply.", "misconception": "Using incorrect formula for secondary maxima intensity"}, {"option_key": "C", "hint": "I₀/9 is close but incorrect. The exact value involves π² in the denominator: 4/(9π²) ≈ 1/22.", "misconception": "Forgetting the π² factor in the intensity formula"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The resolving power of a microscope is given by:", "explanation": "The resolving power of a microscope is the reciprocal of the minimum distance between two point objects that can be just resolved. Using Abbe''s theory, the minimum resolvable distance is d_min = λ/(2n sinθ), where n sinθ is the numerical aperture (NA) of the objective. Therefore, resolving power = 1/d_min = 2n sinθ/λ. Higher numerical aperture and shorter wavelength improve the resolving power.", "correct_answer": "C", "concept_tags": ["resolving-power-microscope", "numerical-aperture", "limit-of-resolution"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-09", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "D/(1.22λ)", "is_correct": false}, {"key": "B", "text": "λ/(2n sinθ)", "is_correct": false}, {"key": "C", "text": "2n sinθ/λ", "is_correct": true}, {"key": "D", "text": "1.22λ/D", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "D/(1.22λ) is the resolving power of a telescope, not a microscope. Telescope resolution depends on the objective diameter D.", "misconception": "Confusing telescope resolving power formula with microscope"}, {"option_key": "B", "hint": "λ/(2n sinθ) is the limit of resolution (minimum resolvable distance), not the resolving power itself. Resolving power is the reciprocal of this.", "misconception": "Confusing limit of resolution with resolving power"}, {"option_key": "D", "hint": "1.22λ/D is the limit of resolution of a telescope (minimum resolvable angle), not the resolving power of a microscope.", "misconception": "Mixing up telescope and microscope resolution formulae"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A diffraction grating has 5000 lines per cm. The angular separation between the first order maxima of two spectral lines of wavelengths 5890 Å and 5896 Å is approximately:", "explanation": "The grating equation is d sinθ = nλ. The grating spacing d = 1/5000 cm = 2 × 10⁻⁴ cm = 2 × 10⁻⁶ m. For first order (n = 1): sinθ₁ = λ₁/d = 5890 × 10⁻¹⁰ / (2 × 10⁻⁶) = 0.2945 and sinθ₂ = 5896 × 10⁻¹⁰ / (2 × 10⁻⁶) = 0.2948. The angular separation dθ ≈ (d(sinθ))/cosθ. Since Δ(sinθ) = 3 × 10⁻⁴ and cosθ ≈ cos(17.1°) ≈ 0.9554, we get dθ ≈ 3 × 10⁻⁴/0.9554 ≈ 3.14 × 10⁻⁴ rad ≈ 0.01°. So approximately 0.01°.", "correct_answer": "B", "concept_tags": ["diffraction-grating", "angular-separation", "spectral-lines"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-10", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "0.1°", "is_correct": false}, {"key": "B", "text": "0.01°", "is_correct": true}, {"key": "C", "text": "1°", "is_correct": false}, {"key": "D", "text": "0.001°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.1° is ten times too large. The wavelength difference is only 6 Å, which produces a very small angular separation in first order.", "misconception": "Error in order of magnitude calculation"}, {"option_key": "C", "hint": "1° is far too large for such a small wavelength difference of just 6 Å.", "misconception": "Gross overestimation of angular separation"}, {"option_key": "D", "hint": "0.001° is ten times too small. Recheck the calculation of sinθ difference and the conversion to degrees.", "misconception": "Error in unit conversion from radians to degrees"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A telescope has an objective lens of diameter 200 cm. The minimum angular separation between two stars that can just be resolved by this telescope, for light of wavelength 5500 Å, is approximately:", "explanation": "By Rayleigh''s criterion, the minimum angular separation θ = 1.22λ/D. Given: λ = 5500 Å = 5.5 × 10⁻⁷ m and D = 200 cm = 2 m. Therefore, θ = 1.22 × 5.5 × 10⁻⁷ / 2 = 1.22 × 2.75 × 10⁻⁷ = 3.355 × 10⁻⁷ rad ≈ 3.36 × 10⁻⁷ rad.", "correct_answer": "A", "concept_tags": ["rayleigh-criterion", "telescope-resolution", "numerical-problem"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-11", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "3.36 × 10⁻⁷ rad", "is_correct": true}, {"key": "B", "text": "6.72 × 10⁻⁷ rad", "is_correct": false}, {"key": "C", "text": "3.36 × 10⁻⁵ rad", "is_correct": false}, {"key": "D", "text": "1.68 × 10⁻⁷ rad", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "6.72 × 10⁻⁷ rad is double the correct answer. You may have used D = 1 m instead of D = 2 m.", "misconception": "Incorrect unit conversion of diameter from cm to m"}, {"option_key": "C", "hint": "This answer is 100 times too large. Check your unit conversion of the wavelength from angstrom to metres.", "misconception": "Error in converting angstroms to metres"}, {"option_key": "D", "hint": "1.68 × 10⁻⁷ is half the correct answer. You may have used D = 4 m or missed the factor 1.22.", "misconception": "Computational error with the 1.22 factor"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A diffraction grating has 6000 lines/cm. The maximum number of orders visible with light of wavelength 5000 Å is:", "explanation": "The grating equation is d sinθ = nλ. The maximum order occurs when sinθ = 1 (i.e., θ = 90°). The grating spacing d = 1/6000 cm = 1.667 × 10⁻⁴ cm = 1.667 × 10⁻⁶ m. Maximum order n_max = d/λ = 1.667 × 10⁻⁶ / (5 × 10⁻⁷) = 3.33. Since n must be an integer, the maximum order is n = 3. Counting both sides of the central maximum and the central maximum itself, the total number of orders visible is 2 × 3 + 1 = 7. However, when asking for the maximum order number, it is 3.", "correct_answer": "D", "concept_tags": ["diffraction-grating", "maximum-order", "grating-equation"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-12", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "apply", "options": [{"key": "A", "text": "5", "is_correct": false}, {"key": "B", "text": "4", "is_correct": false}, {"key": "C", "text": "2", "is_correct": false}, {"key": "D", "text": "3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "n_max = d/λ = 3.33, so n cannot exceed 3. A value of 5 would require sinθ > 1, which is impossible.", "misconception": "Forgetting that sinθ cannot exceed 1"}, {"option_key": "B", "hint": "n = 4 would require sinθ = 4λ/d = 4/3.33 = 1.2, which exceeds 1 and is physically impossible.", "misconception": "Rounding up instead of down for maximum integer order"}, {"option_key": "C", "hint": "n = 2 is an underestimate. Since d/λ = 3.33, the third order (n = 3) is still possible as sinθ = 0.9 < 1.", "misconception": "Incorrectly computing d/λ or taking too conservative an estimate"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The resolving power of a telescope increases with increase in the diameter of its objective lens.\nReason (R): The limit of resolution of a telescope is given by θ = 1.22λ/D, where D is the diameter of the objective.", "explanation": "The assertion is correct: increasing the diameter D of the objective lens decreases the minimum resolvable angle θ = 1.22λ/D, which means the telescope can resolve finer angular details, i.e., its resolving power increases. The reason is also correct: the formula θ = 1.22λ/D is indeed Rayleigh''s criterion for the limit of resolution of a telescope. Moreover, the reason correctly explains why the assertion is true — as D increases, θ decreases, so resolving power (which is 1/θ or D/1.22λ) increases.", "correct_answer": "A", "concept_tags": ["resolving-power-telescope", "rayleigh-criterion", "objective-diameter"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-13", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion: since θ = 1.22λ/D, increasing D decreases θ, hence increasing resolving power. The reason IS the explanation.", "misconception": "Failing to recognise the direct causal link between the formula and the assertion"}, {"option_key": "C", "hint": "The formula θ = 1.22λ/D is a well-established result (Rayleigh''s criterion) and is correct.", "misconception": "Doubting the validity of Rayleigh''s criterion"}, {"option_key": "D", "hint": "The assertion is a well-known fact: larger telescope objectives provide better angular resolution.", "misconception": "Confusing resolving power with magnifying power"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): In a single slit diffraction experiment, if the slit width is made very large compared to the wavelength, the diffraction pattern disappears and the screen is uniformly illuminated.\nReason (R): Diffraction effects are significant only when the size of the obstacle or aperture is comparable to the wavelength of light.", "explanation": "The assertion is correct: when the slit width ''a'' is much larger than the wavelength λ (a >> λ), the angular width of the central maximum 2λ/a becomes extremely small, essentially approaching zero. The diffraction fringes become so narrow and closely spaced that they are unobservable, and the light appears to travel in straight lines producing a uniformly illuminated region behind the slit (geometric shadow limit). The reason is also correct: diffraction is most prominent when the aperture size is of the order of the wavelength. Furthermore, the reason correctly explains the assertion — when ''a'' >> λ, the aperture is no longer comparable to the wavelength, so diffraction effects become negligible.", "correct_answer": "A", "concept_tags": ["slit-width-effect", "diffraction-condition", "wavelength-comparison"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-14", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason explains exactly why the diffraction pattern disappears: when the slit is much larger than λ, the aperture size is no longer comparable to the wavelength, making diffraction negligible. This is a direct explanation.", "misconception": "Not seeing the direct causal connection between the two statements"}, {"option_key": "C", "hint": "The reason is a well-established principle in wave optics and is correct. Diffraction is indeed most noticeable when aperture size is comparable to wavelength.", "misconception": "Incorrectly rejecting a fundamental diffraction principle"}, {"option_key": "D", "hint": "The assertion is correct. In the limit a >> λ, the angular spread 2λ/a → 0, and the pattern merges into uniform illumination.", "misconception": "Thinking diffraction always occurs regardless of slit width to wavelength ratio"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\nA. Resolving power of telescope\nB. Limit of resolution of microscope\nC. Angular width of central maximum (single slit)\nD. Condition for nth minimum (single slit)\n\nColumn II:\n1. a sin θ = nλ\n2. D/(1.22λ)\n3. λ/(2n sinθ)\n4. 2λ/a", "explanation": "A-2: The resolving power of a telescope is D/(1.22λ), where D is the objective diameter. B-3: The limit of resolution of a microscope is d_min = λ/(2n sinθ), where n sinθ is the numerical aperture. C-4: The angular width of the central maximum in single slit diffraction is 2λ/a. D-1: The condition for the nth minimum in single slit diffraction is a sin θ = nλ.", "correct_answer": "B", "concept_tags": ["resolving-power", "diffraction-formulae", "matching-type"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-15", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "C", "text": "A-3, B-2, C-1, D-4", "is_correct": false}, {"key": "D", "text": "A-4, B-1, C-2, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly matches B (microscope limit of resolution) with 4 (2λ/a). The formula 2λ/a is the angular width of the central maximum, not the microscope resolution.", "misconception": "Confusing diffraction angular width formula with microscope resolution"}, {"option_key": "C", "hint": "A-3 would mean the telescope resolving power is λ/(2n sinθ), which is actually the microscope''s limit of resolution formula.", "misconception": "Swapping telescope and microscope formulae"}, {"option_key": "D", "hint": "This matching is entirely wrong. A-4 would assign the angular width formula to telescope resolving power.", "misconception": "Randomly assigning formulae without understanding their physical meaning"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\nA. Fresnel diffraction\nB. Fraunhofer diffraction\nC. Diffraction grating resolving power\nD. Width of central maximum on screen (single slit)\n\nColumn II:\n1. 2λD/a (where D is slit-to-screen distance)\n2. nN (where n is order and N is total number of slits)\n3. Source and screen at infinite distance\n4. Source or screen at finite distance", "explanation": "A-4: In Fresnel diffraction, either the source or the screen (or both) is at a finite distance from the diffracting element. B-3: In Fraunhofer diffraction, both source and screen are effectively at infinite distance (parallel incident rays and observation at infinity or focal plane of lens). C-2: The resolving power of a diffraction grating is nN, where n is the order of diffraction and N is the total number of slits. D-1: The linear width of the central maximum on the screen in single slit diffraction is 2λD/a, where D is the distance from the slit to the screen.", "correct_answer": "C", "concept_tags": ["fresnel-fraunhofer-comparison", "grating-resolving-power", "central-maximum-width"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-16", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-4, B-3, C-1, D-2", "is_correct": false}, {"key": "C", "text": "A-4, B-3, C-2, D-1", "is_correct": true}, {"key": "D", "text": "A-3, B-4, C-1, D-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-3 says Fresnel diffraction has source at infinite distance, but that describes Fraunhofer diffraction. Fresnel involves finite distances.", "misconception": "Swapping Fresnel and Fraunhofer diffraction conditions"}, {"option_key": "B", "hint": "C-1 would mean grating resolving power is 2λD/a, which is actually the linear width of the central maximum, not resolving power.", "misconception": "Confusing the linear width formula with resolving power"}, {"option_key": "D", "hint": "This swaps Fresnel and Fraunhofer conditions and also swaps the resolving power and width formulae.", "misconception": "Multiple misidentifications of Fresnel/Fraunhofer and grating properties"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In single slit diffraction, the central maximum is twice as wide as the secondary maxima.", "explanation": "This statement is TRUE. In single slit Fraunhofer diffraction, the minima occur at angles given by a sinθ = nλ (n = ±1, ±2, ...). The central maximum extends from the first minimum on one side (θ = -λ/a) to the first minimum on the other side (θ = +λ/a), giving an angular width of 2λ/a. Each secondary maximum has an angular width of approximately λ/a (the spacing between consecutive minima). Therefore, the central maximum is twice the width of any secondary maximum.", "correct_answer": "A", "concept_tags": ["central-maximum", "secondary-maxima", "angular-width"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-17", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The central maximum spans from -λ/a to +λ/a (width = 2λ/a), while each secondary maximum spans about λ/a. The ratio is indeed 2:1.", "misconception": "Thinking all maxima in diffraction have equal width"}, {"option_key": "C", "hint": "This is a placeholder option.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The resolving power of a microscope increases when the wavelength of light used is increased.", "explanation": "This statement is FALSE. The resolving power of a microscope is given by RP = 2n sinθ/λ, where n sinθ is the numerical aperture. Since λ appears in the denominator, increasing the wavelength decreases the resolving power. To increase the resolving power of a microscope, one should use light of shorter wavelength (such as ultraviolet light or electron beams in electron microscopes).", "correct_answer": "B", "concept_tags": ["resolving-power-microscope", "wavelength-effect", "inverse-relationship"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-18", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since RP = 2n sinθ/λ, increasing λ makes the denominator larger, reducing resolving power. Shorter wavelengths improve resolution.", "misconception": "Thinking wavelength and resolving power are directly proportional"}, {"option_key": "C", "hint": "This is a placeholder option.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The resolving power of a diffraction grating in the nth order with a total of N slits is given by RP = _____.", "explanation": "The resolving power of a diffraction grating is defined as RP = λ/Δλ, where Δλ is the minimum resolvable wavelength difference. According to the Rayleigh criterion applied to a diffraction grating, the resolving power equals the product of the order of diffraction (n) and the total number of slits (N): RP = nN. This means higher order diffraction and more slits both improve the ability to distinguish closely spaced spectral lines.", "correct_answer": "D", "concept_tags": ["diffraction-grating", "resolving-power-grating", "chromatic-resolving-power"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-19", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "N/n", "is_correct": false}, {"key": "B", "text": "n/N", "is_correct": false}, {"key": "C", "text": "(n + N)", "is_correct": false}, {"key": "D", "text": "nN", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "N/n would mean resolving power decreases with higher order, which contradicts the fact that higher order gives better spectral resolution.", "misconception": "Inverting the relationship between order number and resolving power"}, {"option_key": "B", "hint": "n/N would give a very small number for large N, but more slits should increase (not decrease) resolving power.", "misconception": "Swapping numerator and denominator"}, {"option_key": "C", "hint": "The resolving power is a product, not a sum. The formula RP = nN is derived from the condition for just resolving two wavelengths.", "misconception": "Confusing multiplication with addition in the formula"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-diffraction", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "An astronomer is observing binary stars (two stars very close together) using two telescopes: Telescope P with an objective diameter of 100 cm and Telescope Q with an objective diameter of 50 cm. Both observations are made using light of wavelength 5500 Å. If Telescope P can just resolve the two stars, what can be said about the observation through Telescope Q?", "explanation": "The minimum angular separation that can be resolved is θ = 1.22λ/D. For Telescope P: θ_P = 1.22 × 5.5 × 10⁻⁷ / 1.0 = 6.71 × 10⁻⁷ rad. For Telescope Q: θ_Q = 1.22 × 5.5 × 10⁻⁷ / 0.5 = 1.342 × 10⁻⁶ rad. Since Q has half the diameter, its limit of resolution is twice that of P. If Telescope P just resolves the two stars (their angular separation equals θ_P), then Telescope Q cannot resolve them because its limit of resolution θ_Q = 2θ_P is larger than the actual angular separation of the stars. The two stars would appear as a single unresolved image through Telescope Q.", "correct_answer": "C", "concept_tags": ["rayleigh-criterion", "telescope-resolution", "scenario-based", "binary-stars"], "payload": {"question_id": "cuet-phy-waveopt-diffraction-20", "subtopic": "Diffraction of Light", "topic_name": "Diffraction of Light", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Telescope Q will also just resolve the two stars", "is_correct": false}, {"key": "B", "text": "Telescope Q will resolve the stars more clearly than Telescope P", "is_correct": false}, {"key": "C", "text": "Telescope Q will not be able to resolve the two stars", "is_correct": true}, {"key": "D", "text": "The resolving power of both telescopes is the same since they use the same wavelength", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Telescope Q has a smaller objective (50 cm vs 100 cm), so its limit of resolution θ = 1.22λ/D is larger. It cannot match Telescope P''s resolving ability.", "misconception": "Ignoring the effect of objective diameter on resolution"}, {"option_key": "B", "hint": "A smaller objective diameter gives worse (not better) resolution. Telescope Q''s minimum resolvable angle is double that of Telescope P.", "misconception": "Thinking smaller telescopes have better resolution"}, {"option_key": "D", "hint": "Resolving power depends on both λ and D. Although the wavelength is the same, the different diameters give different resolving powers: RP = D/(1.22λ).", "misconception": "Thinking resolving power depends only on wavelength"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In Young''s double slit experiment, the fringe width is given by:", "explanation": "The fringe width in Young''s double slit experiment is given by the formula beta = lambdaD/d, where lambda is the wavelength of light, D is the distance between the slits and the screen, and d is the separation between the two slits. This formula is derived from the geometry of the experiment and the condition for constructive interference.", "correct_answer": "A", "concept_tags": ["fringe-width", "ydse-formula", "wave-optics"], "payload": {"question_id": "cuet-phy-waveopt-interference-01", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "beta = lambdaD/d", "is_correct": true}, {"key": "B", "text": "beta = lambdad/D", "is_correct": false}, {"key": "C", "text": "beta = d/lambdaD", "is_correct": false}, {"key": "D", "text": "beta = D/lambdad", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This formula has d and D interchanged. Fringe width increases with screen distance D and decreases with slit separation d, so D must be in the numerator and d in the denominator.", "misconception": "Interchanging the roles of slit separation and screen distance"}, {"option_key": "C", "hint": "This places wavelength in the denominator. Since fringe width increases with wavelength, lambda must be in the numerator.", "misconception": "Inverting the fringe width formula"}, {"option_key": "D", "hint": "This formula has all three quantities incorrectly placed. Recall that fringe width is directly proportional to both lambda and D.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "For sustained interference of light, the two sources must be:", "explanation": "Sustained (or stable) interference requires coherent sources, meaning the two sources must emit light waves of the same frequency and maintain a constant phase difference. Incoherent sources produce randomly varying phase differences, causing the interference pattern to change rapidly and average out, making it invisible.", "correct_answer": "B", "concept_tags": ["coherent-sources", "sustained-interference", "conditions-for-interference"], "payload": {"question_id": "cuet-phy-waveopt-interference-02", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "Of different frequencies with random phase", "is_correct": false}, {"key": "B", "text": "Coherent, i.e., having the same frequency and a constant phase difference", "is_correct": true}, {"key": "C", "text": "Very bright and of the same intensity", "is_correct": false}, {"key": "D", "text": "Polarised in mutually perpendicular directions", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Different frequencies mean the phase difference changes continuously, so no sustained fringe pattern can form.", "misconception": "Thinking that any two light sources can produce sustained interference"}, {"option_key": "C", "hint": "Equal intensity is not a necessary condition for interference. Unequal intensities still produce interference, only with reduced contrast (non-zero minima).", "misconception": "Confusing intensity condition with coherence condition"}, {"option_key": "D", "hint": "Perpendicular polarisations would prevent interference entirely. For interference, the waves should have the same state of polarisation, not perpendicular.", "misconception": "Confusing polarisation with coherence requirements"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In Young''s double slit experiment, if the slit separation d is doubled while keeping all other parameters constant, the fringe width will:", "explanation": "The fringe width beta = lambdaD/d. If d is doubled, beta becomes lambdaD/(2d) = beta/2. So the fringe width is halved. Increasing the slit separation brings the fringes closer together.", "correct_answer": "C", "concept_tags": ["fringe-width", "slit-separation", "ydse-parameters"], "payload": {"question_id": "cuet-phy-waveopt-interference-03", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "understand", "options": [{"key": "A", "text": "Become double", "is_correct": false}, {"key": "B", "text": "Remain the same", "is_correct": false}, {"key": "C", "text": "Become half", "is_correct": true}, {"key": "D", "text": "Become four times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Doubling d would double the fringe width only if d were in the numerator. Since beta = lambdaD/d, d is in the denominator, so increasing d decreases beta.", "misconception": "Thinking fringe width is directly proportional to slit separation"}, {"option_key": "B", "hint": "Fringe width depends inversely on slit separation, so changing d must change beta.", "misconception": "Ignoring the dependence of fringe width on slit separation"}, {"option_key": "D", "hint": "A fourfold change would require squaring, but the relationship is beta inversely proportional to d (first power), not d squared.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The path difference between two waves reaching a point on the screen in Young''s experiment for the third bright fringe is:", "explanation": "For bright fringes (constructive interference), the path difference = n*lambda, where n is the order of the fringe. For the third bright fringe, n = 3, so the path difference = 3*lambda.", "correct_answer": "D", "concept_tags": ["path-difference", "bright-fringe", "constructive-interference"], "payload": {"question_id": "cuet-phy-waveopt-interference-04", "subtopic": "Interference of Light", "topic_name": "Interference of Light", "bloom_level": "remember", "options": [{"key": "A", "text": "lambda/2", "is_correct": false}, {"key": "B", "text": "lambda", "is_correct": false}, {"key": "C", "text": "5*lambda/2", "is_correct": false}, {"key": "D", "text": "3*lambda", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "lambda/2 is the path difference for the first dark fringe (first minimum), not a bright fringe.", "misconception": "Confusing conditions for bright and dark fringes"}, {"option_key": "B", "hint": "lambda corresponds to the first bright fringe (n = 1), not the third.", "misconception": "Confusing fringe order"}, {"option_key": "C", "hint": "5*lambda/2 is the path difference for the third dark fringe (n = 3 in the dark fringe formula (2n-1)*lambda/2), not the third bright fringe.", "misconception": "Using the dark fringe formula instead of the bright fringe formula"}]}}]'::jsonb, 'deploy-2026-03-05-b13');

